INSERT INTO "books" VALUES('',0,'','Czank_Georgina--FD.jpg','','',1,0,0,2,'',0,'',10,40,'','',NULL,NULL,'',60,0,NULL,0,7,2008,15,'Czank Georgina','Ihlet meséi','978-963-87819-2-5',1,'','1','A5',80,'0',1290,1,'#LA3','Czank-Georgina','http://www.konyvesbolt.online/spd/978-963-87819-2-5/Czank-Georgina-Ihlet-mesei-2008','','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-7-0','Czank Georgina, 2376, Hernád Gyóni út 86.','czg03@freemail.hu','','Mikor a költő ott ül szobájában, egy hűvös ködös hajnalon, egyetlen barátja a szó marad. A szó, melyet rímekbe foglalva vés le egy gyűrött papírra, és lelkében érzi a szavak súlyát, mik gyógyító pirulaként gurulnak le torkán.
INSERT INTO "books" VALUES('',0,'','JokaiUtazas-FD.jpg','','',1,0,15,6,'',0,'','','','',50,NULL,NULL,1000,'',2,NULL,0,3,2008,16,'Jókai Mór','Útleírások','978-963-87769-0-7',2,'','1','A5',260,'1',1990,3,'#LA4#','http://adlibrum.hu/Jokai','http://www.konyvesbolt.online/spd/978-963-87769-0-7/Jokai-Mor-Utleirasok-Ad-Librum-2008','','','http://www.fo.hu/hu/konyv/ismeretterjeszto_1/terkepek_utikonyvek/utleirasok_regi_utazasok','','','','',3,0,0,0,0,0,0,'Array-0-0','2008-3-0','','soos.gabor@topiksoft.hu','Jókai utazásai Erdélyben, Magyarországon és külföldön - a maga sajátos stílusában.','``Vannak vidékek, amiknek igéző hatása az emberi kedélyre el nem tagadható, amiknek múltja belesugall a jelenbe. Ország, világ, korszellem átalakul, idomul az idővel, az a vidék maga külön is alakít, idomít, s hagyományos befolyását nem szünteti meg, s mint egy örökké tartó álom, belerémlik az ébrenlétbe.``
