INSERT INTO "books" VALUES('',0,'','KissMonikaDorota-FD.jpg','','',1,1,0,40,'',1,'',10,40,'','',NULL,NULL,'',50,0,NULL,27,6,2008,36,'Kiss Mónika Dorota','Közhatalmi intézmények a helyi önkormányzati jogrendszerben','978-963-87830-5-9',1,'','1','A5',160,'0',1990,1,'#LB2#','Kiss-Monika-Dorota','http://www.konyvesbolt.online/spd/978-963-87830-5-9/Kiss-Monika-Dorota-Kozhatalmi-intezmenyek-a-helyi-','','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-6-27','Dr. Kiss Mónika Dorota; Siójut-8652, Dobó Katica u. 8.','krasnoludek@freemail.hu','','A közhatalmi közösségi formák jogi kérdéskörei és aspektusai olyan területei a helyi önkormányzati jogrendszernek, amelyek általánosan közvetett és közvetlen alakzatokra tagolódnak. Ebből következően a szerepük, az intenzitásuk eltérő és változatos. Olyan területei ezek az önkormányzati jognak, ahol, amelyekkel kapcsolatban a képviselő-testületek helyi jogszabályalkotásának tükröződnie kell.
