INSERT INTO "books" VALUES('',0,'','SebestyenAdam-FD.jpg','','',1,0,0,37,'',1,'',10,40,'','',NULL,NULL,'',100,0,NULL,0,5,2008,38,'Sebestyén Ádám','Gyógyító praktikák: Néprajzi gyűjtés a bukovinai székelyeknél','978-963-87830-7-3',1,'','1','A5',168,'0',2990,1,'#LC, LGrégi salgóVIII#','Sebestyen-Adam','http://www.konyvesbolt.online/spd/978-963-87830-7-3/Sebestyen-Adam-Gyogyito-praktikak-Neprajzi-gyujtes','http://bookline.hu/product/home!execute.action?id=73368&type=22&_v=Sebestyen_Adam_Gyogyito_praktikak','','http://www.fo.hu/hu/konyv/tovabbi_konyveink/gyogyito_praktikak','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-5-0','Sebestyén Imre Dezső, 7100 Szekszárd, Csalogány u. 18.','sms007@freemail.hu','','A Magyarországon élő bukovinai székelyek erősen kötődnek a bukovinai szülőföldhöz. Őseik a Kárpátokon túl születtek, éltek, majd jöttek Magyarországra. Megjárták a saját kálváriájukat, hogy immár 60 évet meghaladóan itthon lehessenek otthon. Még néhány idős székely él közöttünk, aki otthon Bukovinában s mások Bácskában születtek. Ők is elmúltak már 60-70 évesek! Így már az sincs, akitől kérdezzünk! Ez is korlátozza az eredeti bukovinai székely hagyományok további feltárását.
INSERT INTO "books" VALUES('',0,'','TothAkos-FD.jpg','','',1,1,11,13,'',0,'',10,40,'','',NULL,NULL,'',20,0,NULL,0,5,2008,39,'Tóth Ákos','Gyémántkutyák','978-963-87830-8-0',1,'','1','A5',120,'0',1590,1,'#LB6#','Gyemantkutyak','http://www.konyvesbolt.online/spd/978-963-87830-8-0/Toth-Akos-Gyemantkutyak-2008','','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-5-0','','','','','2012nov: 1 pld.
INSERT INTO "books" VALUES('',0,'','NyirfasDedi-FD.jpg','','',1,0,0,8,'',0,'',10,40,'','',NULL,NULL,'',100,0,NULL,0,6,2008,40,'Nyírfás Pyrker Dezső','A dédi öröksége','978-963-87830-9-7',1,'','1','A5',404,'0',2590,1,'#LB4#','Nyirfas-Dezso','http://www.konyvesbolt.online/spd/978-963-87830-9-7/Nyirfas-Pyrker-Dezso-A-dedi-oroksege-2008','http://bookline.hu/product/home!execute.action?id=73366&type=22&_v=Nyirfas_Dezso_A_dedi_oroksege','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-6-0','1172 Budapest, Algír u. 58.','nyird@t-online.hu','A dédi ládája és a háborús menekülés.','"A szekér nem volt nagy, amolyan közönséges parasztszekér volt, amilyen szinte minden portán akadt, amíg el nem rekvirálták a katonák. Ezt már, jól látszott, annyira kikezdte szú, hogy talán azért maradt meg a gazdának. Édesapám mégis bátran felpakolt mindent, amit édesanyám mondott, így hát senkinek sem volt kényelmes ülőhelye a kosarakon, batyukon és ládákon, csak annak a szigorú embernek, aki a lovakat hajtotta. Arra emlékszem, hogy akkora kezei voltak, mint egy szénázó favilla. A jobbikban a gyeplőt tartotta, a másikban az ostort. Nem kímélte a lovakat. Lépten-nyomon megcsapta, hol az egyiket, hol a másikat. Néha úgy éreztem, hogy nekem is fáj, mikor végighúzott a lovak tomporán. Közben megvolt a saját bajom. Az a kis vaspántos láda, amin kucorogtam, alaposan belenyomódott a fenekembe, és lábaimat sem tudtam jól mozgatni, hol az egyik zsibbadt el, hol a másik. Mindenféle holmik voltak körülöttem, és csak egy arasznyi résen láthattam előre, különben pedig csak az eget és a hajnali fényben fürdő felhőket láthattam. A szekéren hátul, a saroglyában Dédinek alakított ki helyet édesapám, körül is rakta dunyhával, még a nagy csergét is aláterítette, mert Dédi már öreg is volt, beteg is volt, járni meg alig tudott, így hát egy kicsit kényeztetni kellett."','2012nov: 3 pld.
