INSERT INTO "books" VALUES('',0,'','','','',0,0,0,12,'',0,'',40,75,'','',NULL,NULL,'','',0,NULL,0,10,2008,68,'Szabó Mária Gizella','Szerelmi zsákutcák avagy száz békát megcsókoltam','978-963-06-5800-3',1,'','1','A5',204,'0',1990,1,'LEZÁRT: ÚJ TÉTELT MÁR NEM ÍRUNK BE! Csak a webbolt miatt nincs lezárva státusza.','Szabo-Maria-Gizella','','http://bookline.hu/product/home!execute.action?id=75588&type=22&_v=Szabo_Maria_Gizella_Szerelmi_zsakutcak_avagy_szaz_bekat_megcsokoltam','','','','','','',3,0,0,0,0,0,0,'Array-0-0','2008-10-0','Szentiné Szabó Mária Gizella, 70 2013392, 6900 Makó Baross u 8.','mariagizella@citromail.hu','','Kiről szól ez a könyv? Rólad, rólam és mindazokról, akik kitartóan bíztak abban, hogy megtalálják a „királyfit”. Tudjuk, az út rögös, de ezer tapasztalatot, szépséget és titkot rejt számunkra, mialatt megismerjük a párkapcsolatok rejtelmeit, és főleg saját magunkat. Márta, a főszereplő egy elvált, kétgyermekes, még mindig szép ex-vállalkozó, aki az eltűnő szépség árnyékában visszatekint szerelmi életére, de a történések most is változatlanul zajlanak körülötte. Keresi a választ, hogy a dolgok miért történtek így. Bejárhatjuk az utat Mártával, nevetve, sírva, remélve és csalódva, némi humorral és iróniával szemlélve a világot, miközben a saját kérdésünkre is megtalálhatjuk a választ.','Ez került az új webboltba, hogy látszódjon az árcsökkentés. [2012-01-20]
