INSERT INTO "books" VALUES('',0,'','','',0,0,0,0,8,'http://books.google.hu/books?printsec=frontcover&id=zmLvgcwwkJIC#v=onepage&q=&f=false',1,'',5,35,'',18,5,921,200,207,1,NULL,0,11,2008,80,'Bagi Mariann','Írországi álmok','978-963-9888-36-4',2,'','1','140x200 mm',512,'0',3990,2,'#LA2, LGIV#  T:G','Bagi-Mariann','','http://bookline.hu/product/home!execute.action?id=75827&type=22&_v=Bagi_Mariann_Irorszagi_almok','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/irorszagi_almok','','','','',5,3,0,6,4,0,0,'Array-0-0','2008-11-0','5435 Martfű, Munkácsy út 44.','bagimariann@gmail.com','','Egy mesevilág: zöldellő rétek, lágy dombok és szabados, vidám emberek földje – kit ne varázsolt volna még el Írország koboldjainak és tündéreinek története? Írország valódi történelme azonban kevésbé idilli – mélyről feltörő ellentétek és harcok hazájává vált a múlt század elején. A regény ezt az átmenetet, „felébredést” ragadja meg több hazafias ír fiatal – köztük Ian Dalton – rövid életén keresztül, akiknek dublini és belfasti harcokon át vezet rögös útja a felismeréshez, melyik is a legértékesebb az álmaik közül.','Lezárva 2015.11.19.
INSERT INTO "books" VALUES('',0,'','',264,0,0,0,0,9,'',0,'',0,0,'',21,20,257,500,500,1,NULL,0,11,2008,81,'Gáti Vilmos','Fedésben - A terroristák nyomában (politikai krimi)','978-963-9888-37-1',2,'','1','A5',194,'0',2490,2,'#LE3,LGIV#','Gati-Vilmos','http://www.konyvesbolt.online/spd/978-963-9888-37-1/Gati-Vilmos-Fedesben---A-terroristak-nyomaban-poli','http://bookline.hu/product/home!execute.action?id=75825&type=22&_v=Gati_Vilmos_Fedesben_A_terroristak_nyomaban','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/fedesben_a_magyar_katonai_felderites_a_nemzetkozi_alvilag_es_az_al_kaida','http://www.konyvesbolt.online/spd/978-963-9888-37-1/Gati-Vilmos-Fedesben---A-terroristak-nyomaban-poli','','Gati_Vilmos','AdLibrum--Gati_Vilmos--Fedesben--Kulonnyomat.pdf',3,0,0,0,0,0,0,'Array-0-0','2008-11-0','','agenda.alapitvany@t-online.hu','Titkosszolgálati küzdelem az alvilág és az Al-Kaida összefonódása ellen.','Magyarország nem szerepel az al-Kaida közvetlen célpontjai között, de a fordulatos alvilági konfliktus váratlan következményeként tesz szert a magyar szolgálat kulcsszerepre a történetben.
INSERT INTO "books" VALUES('',0,'','','','',0,0,0,11,'',0,'',5,20,'',15,5,494,100,107,1,NULL,0,10,2008,82,'Christian Crow','A polip barlangjában','978-963-9888-38-8',2,'','1','A5',286,'0',2990,2,'#A5 Kovács Krisztián Duplikálva mint 396.','http://adlibrum.hu/Christian-Crow/','','http://bookline.hu/product/home!execute.action?id=76069&type=22&_v=Crow_Christian_A_polip_barlangjaban','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/a_polip_barlangjaban','','','','',5,3,0,0,0,0,0,'Array-0-0','2008-10-0','','christico@freemail.hu','','Gabriel Cromwell nem az emberiség mintapéldánya. Felesége elvált tőle, az apja kitagadta, de szerencsére legalább alkoholizmusából sikerült kigyógyulnia. Mindezek ellenére munkáját tisztességesen végzi, s élete a már lassan megszokott, sanyarú, agglegényi mederben csordogál - egészen egy borús, esős, májusi estéig.
