INSERT INTO "books" VALUES('',0,'','Klicsu_Anna_II-FD.jpg','','',1,0,0,12,'',0,'',10,40,'',21,5,482,300,310,1,NULL,0,11,2008,84,'Klicsu Anna','Matthew vs. Patrick (avagy Shannon döntésképtelensége férfiügyben)','978-963-9888-39-5',2,'','1','140x200 mm',276,'0',2490,2,'#LB6 T:G','Klicsu-Anna','http://www.konyvesbolt.online/spd/978-963-9888-39-5/Klicsu-Anna-Matthew-vs--Patrick-avagy-Shannon-dont','http://bookline.hu/product/home!execute.action?id=77331&type=22&_v=Klicsu_Anna_Matthew_vs_Patrick_avagy_Shannon_donteskeptelensege_ferfiugyben','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/matthew_vs_patrick_avagy_shannon_donteskeptelensege_ferfi','','','','',3,3,0,0,0,0,0,'Array-0-0','2008-11-0','20/480-6936, 1222 Budapest; Promontor utca 20.','klicsua@citromail.hu','','Shannon Haywire egy olyan nő, aki már annyira utálja az átlagosságot, hogy mindenáron meg akar tőle szabadulni. De leginkább attól, hogy ő ne legyen az. Ám ezt nehezíti az a tény, hogy ő maga egy igazán szerencsétlen nő. Ha döntenie kell egy helyzetben, akkor biztosra vehető, hogy a legrosszabb megoldást választja. 
