INSERT INTO "books" VALUES('',0,'','','',0,0,0,0,0,'',1,'','','','','',NULL,NULL,'','',0,NULL,0,0,2008,88,'Rácz Györgyi Katalin','Nemzetközi Nőci - Utazás kívülről befelé','',2,'','1','A5',100,'0',1990,0,'','http://adlibrum.hu/Racz-Gyorgyi/','','','','','','','','',4,0,0,0,0,0,0,'Array-0-0','Array-0-0','','','','Ezt a könyvet elsősorban azoknak az embereknek írtam, akik tervezik, hogy külföldön vállalnak munkát, vagy már az ingázó magyarok népes táborába tartoznak.
INSERT INTO "books" VALUES('',0,'','Csiszar_Maria--Elsz_Barackvirag--FD.jpg',180,0,1,0,0,17,'',1,'',10,40,'',21,20,320,300,300,1,NULL,0,11,2008,89,'Csiszár Mária','Élsz, Barackvirág!','978-963-9888-43-2',2,'','1','A5',138,'0',2190,2,'#LA3, LGI#','Csiszar-Maria','http://www.konyvesbolt.online/spd/978-963-9888-43-2/Csiszar-Maria-Elsz-Barackvirag-Ad-Librum-2008','http://bookline.hu/product/home!execute.action?id=76591&type=22&_v=Csiszar_Maria_Elsz_Barackvirag_','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/elsz_barackvirag','http://www.konyvesbolt.online/spd/978-963-9888-43-2/Csiszar-Maria-Elsz-Barackvirag-Ad-Librum-2008','','','',3,3,0,0,0,0,0,'Array-0-0','2008-11-0','06-26/335-174, 06-30/285-7279, 2086 Tinnye, István király u. 1.','csimaria@gmail.com','Küzdelem az életképtelennek ítélt babáért. Keresztény könyv ájtatoskodás nélkül, megrázó orvosi történet hatásvadászat nélkül, hiteles korrajz (a Ceauşescu-éra utolsó éve és a rendszerváltás ideje) gyűlöletkeltés nélkül.','﻿(...) Az első nyomásnál már látták a baba fejét, s biztattak, hogy a következő görcsnél megszületik. Éles fájdalom, jóleső elernyedés - és megfagyott körülöttem a levegő. Halk nyöszörgést hallottam, és nem értettem semmit. Magdi fogta a babát, és nézte Imrét, Imre doktor megkövülten állt.
INSERT INTO "books" VALUES('',0,'','Bagolyne_Szucs_Andrea-FD.jpg',120,0,1,0,17,29,'',1,'',10,40,'',50,20,202,500,500,2,NULL,0,12,2008,90,'Bagolyné Szűcs Andrea','Lilla szakácskönyve','978-963-9888-48-7',2,'','1','A5',56,'0',1990,2,'120 g, a megvett példányok másik számon','Bagolyne-Szucs-Andrea','http://www.konyvesbolt.online/spd/978-963-9888-48-7/Bagolyne-Szucs-Andrea-Lilla-szakacskonyve-Ad-Libru','http://bookline.hu/product/home!execute.action?id=77177&type=22&_v=Bagolyne_Szucs_Andrea_Lilla_szakacskonyve','','','http://www.konyvesbolt.online/spd/978-963-9888-48-7/Bagolyne-Szucs-Andrea-Lilla-szakacskonyve-Ad-Libru','','','',3,0,0,0,0,0,0,'Array-0-0','2008-12-0','','bagolyneandi@freemail.hu','Szakácskönyv a nagyon kicsiknek.','Kedves kis kukták! Ez a szakácskönyv a legkisebbeknek készült, akik most vesznek a kezükbe először fakanalat. Bátran vágjatok bele, mert receptjeink útmutatásai alapján  minden kisgyerek - a szülei segitségével - el tudja készíteni ezeket az egyszerű, mutatós, inycsiklandó fogásokat. 
INSERT INTO "books" VALUES('',0,'','Szabo_Daniel-FD.jpg','','',1,2,0,11,'',0,'','',30,'',15,5,356,100,107,1,NULL,0,11,2008,91,'Szabó Dániel','A halál üdvözletét küldi','978-963-9888-47-0',2,'','1','A5',150,'0',2390,2,'','Szabo-Daniel','','','','','','','','',3,0,0,0,0,0,0,'Array-0-0','2008-11-0','06 70/3983237','szada2006@citromail.hu','','Cris Daniels magánnyomozó hullák között kel és fekszik, ám ez még neki is megfekszi a gyomrát. Hívatlan látogatók nézik az ablakot leszállópályának, felrobban a chicagói panellakás, elrabolják Barbara apját, olyan lányokba botlik, akikből kibotlani is nehéz, titokzatos halálesetek történnek, amerre jár, és mindenhol ott van a vészjósló ezüst hajszál.
