INSERT INTO "books" VALUES('',0,'','','',0,0,0,0,41,'',1,'','','','',15,5,794,100,110,1,NULL,2,4,2009,93,'Böhm Edit','A magyar versszavalás története','978-963-9888-93-7',2,'','2','A5',428,'0',3990,2,'#A4','Bohm-Edit','http://www.konyvesbolt.online/spd/978-963-9888-93-7/Bohm-Edit-A-magyar-versszavalas-tortenete-Ad-Libru','http://bookline.hu/product/home!execute.action?id=79731&type=22&_v=Bohm_Edit_A_magyar_versszavalas_tortenete','','','http://www.konyvesbolt.online/spd/978-963-9888-93-7/Bohm-Edit-A-magyar-versszavalas-tortenete-Ad-Libru','','','',3,3,1,9,4,5,1,'2009-2-0','2009-4-2','Némethné Dr. Böhm Edit 70/37-47-282,23/379-564, 2030 Érd, Betonozó u. 15.','edi05@t-online.hu','','Ez a könyv a magyar verselőadás (versszavalás) gyökereit, hagyományait, fejlődésének küzdelmes útját, fontosabb állomásait tárja fel, amivel hozzájárul e művészeti ág vitatott kérdéseinek megválaszolásához. Egyben emléket állít azoknak a képviselőinek, akik a különböző korszakokban hittel és odaadással vállalták fel a költészet élőszóbeli közvetítését, de mert művészetük –a színészethez hasonlóan- a pillanat művészete, alakjuk gyorsan eltűnik az emlékezetből. Bemutatja a versek szavalásával kapcsolatos nézetek, elméletek alakulásának folyamatát és utal az egyes korszakok előadóművészeti közegére, sajátos elvárásaira, az irodalmi- és a színházi élettel való összefüggésekre.
INSERT INTO "books" VALUES('',0,'','','','',0,0,18,15,'',1,'',10,40,'',21,20,259,300,400,2,NULL,0,11,2008,94,'Arany Emmi','Ti, kínaiak','978-963-9888-50-0',2,'','1','140x200 mm',106,'0',1990,2,'#LA6,LGIII,IV#  Vincze Edit T&B:szerző','Arany-Emmi','http://www.konyvesbolt.online/spd/978-963-9888-50-0/Arany-Emmi-Ti-kinaiak-Ad-Librum-2008','http://bookline.hu/product/home!execute.action?id=77513&type=22&_v=Arany_Emmi_Ti_kinaiak','','','','','','',3,0,0,0,0,0,0,'Array-0-0','2008-11-0','Vincze Edit, 20/94-29-037, ideiglenes: megszünt, állandó: 1137 Budapest Szent István krt. 30.','vincze@emimail.com','Egy magyar diáklány kalandjai Kínában.','﻿„A változás, az, hogy semmi nem állandó, erre az országra egyértelműen jellemző. Tulajdonképpen ez volt az egyik fő oka, amiért ezt a könyvet megírtam. Szeretném, ha minél többen megismernék az itt élő emberek igazi arcát. A boldogságukat, a könnyeiket, örömüket, bánatukat. Kicsit bepillantanának a mindennapi életükbe, és ezzel közelebb kerülnének ehhez a túlmisztifikált világhoz. Én megszerettem őket. A hibáikkal, rossz tulajdonságaikkal együtt.  Mégis, szívemből szólnak ők, az első perctől fogva. Mert adtak nekem valamit, valamit önmagukból, abból a szemléletből, ahogy ők látják a világot. Sok mindenre tanítottak, és remélem én is hagytam magamból valamit az ő számukra.
(...)
INSERT INTO "books" VALUES('',0,'','',124,0,0,0,12,4,'',0,'',10,30,'',21,5,275,300,300,1,NULL,30,11,2008,95,'Németh György Gábor','Ophelia virágai','978-963-9888-51-7',2,'','1','A5',96,'0',1990,2,'#L §372-n folytatva','Nemeth-Gyorgy','','http://bookline.hu/product/home!execute.action?id=77329&type=22&_v=Nemeth_Gyorgy_Gabor_Ophelia_viragai','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/ophelia_viragai','','','','',5,0,0,0,0,0,0,'Array-0-0','2008-11-30','Dr. Németh György Gábor, 06-30-5023-222, ideiglenes: 1072 Budapest, Dob u. 46/a., állandó: 1121 Budapest, Árnyas út 14.','nemethgyo@freemail.hu','','„Az álmod éjjel játszódik, s te egyedül vagy a gyerekkori otthonodban. Az ágyban fekve arra riadsz fel, hogy valaki odakint járkál a kertben. Leszaladsz a földszintre, és kinézel az ablakon. Eleinte semmit nem látsz, csak a vaksötétet, majd hirtelen egy arc jelenik meg az üveg túloldalán. Egy szőrös férfiarc. A vonásai durvák, a képe sebhelyes, a tekintetéből kegyetlenség árad. Megpróbálja kinyitni az ablakot, de nem jár sikerrel, így hát továbbsiet, hogy keressen egy titkos helyet, ahol bejuthat. Megpróbálod megelőzni. Minden ajtót és ablakot be kell zárnod, mielőtt odaérne. Versenyt futtok egymással. 
