INSERT INTO "books" VALUES('',0,'','','',0,0,0,0,1,'http://books.google.hu/books?printsec=frontcover&id=fRv5fQfs8A8C#v=onepage&q=&f=false',1,'',10,40,'',100,20,350,1000,1000,2,NULL,0,11,2008,97,'Pozsgai Zsolt','Szeretlek, fény - történelmi játékok, társadalmi drámák, bohózatok','978-963-9888-53-1',2,'','1','140x200 mm',368,'0',2990,2,'#LC3,LGVI,LGraklap#   T:G,B:V','http://adlibrum.hu/Pozsgai-Zsolt/','http://www.konyvesbolt.online/spd/978-963-9888-53-1/Pozsgai-Zsolt-Szeretlek-feny---tortenelmi-jatekok-','http://bookline.hu/product/home!execute.action?id=76861&type=22&_v=Pozsgai_Zsolt_Szeretlek_feny','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/vers_drama/szeretlek_feny_tortenelmi_jatekok_tarsadalmi_dramak_boh','http://www.konyvesbolt.online/spd/978-963-9888-53-1/Pozsgai-Zsolt-Szeretlek-feny---tortenelmi-jatekok-','','','',3,0,0,0,0,0,0,'2008-10-0','2008-11-0','ideiglenes: 1021 Budapest, Hüvösvölgyi u. 6. 30-279-1324','pozsgaizsolt@vipmail.hu','','Vak Béla, Mátyás király, Janus Pannonius, Balog úr a nyolcadik kerületből, egy tucat közép-amerikai prostituált, nagyhangú olasz család, klasszikus francia bohózati alakok mind megférnek ebben a kötetben. Pozsgai Zsolt /1960/ legújabb drámakötete a műfaji sokféleség jegyében született. Megtalálható itt érzékeny történelmi színmű, abszurd komédia, társadalmi dráma, bűnügyi játék, és két, álnéven írt bohózat. A szerző egész eddigi életműve a műfaji sokrétűséget képviseli. Eredeti darabjaival, musical-szövegkönyveivel, vagy színpadi átdolgozásaival gyakran találkozhatunk a színházakban. Nem csak itthon, egyre gyakrabban külföldön is. A kötetben található művek egy kivételével már kiállták a színpad próbáját, nagy sikerrel mutatták be, és játszották, vagy játsszák ma is őket. Olvasva is élvezetes  és kitűnő szórakozást nyújtanak.','2009.ZKI:2+236=238+1=239
