INSERT INTO "books" VALUES('',0,'','Metzger_Csaba--A_pszichohistoria_alapjai--FD.jpg',117,'',1,0,0,27,'',0,'',10,40,'',30,5,250,300,320,2,NULL,12,8,2009,105,'Metzger László Csaba','A pszichohistória alapjai','978-963-06-7631-1',1,'','2','A5',68,'0',1990,2,'#LA2,LGIII#','Metzger-Laszlo-Csaba','http://www.konyvesbolt.online/spd/978-963-06-7631-1/Metzger-Laszlo-Csaba-A-pszichohistoria-alapjai-200','http://bookline.hu/product/home!execute.action?id=82365&type=22&_v=Metzger_Laszlo_Csaba_A_pszichohistoria_alapjai','','http://www.fo.hu/hu/konyv/ismeretterjeszto_1/tarsadalomtudomany/a_pszichohistoria_alapjai','','','','',3,3,0,7,4,5,0,'Array-0-0','2009-8-12','5000 Szolnok, Ugar 76/4.  T.: 30/419-3372','tiara@dunaweb.hu','','Ebben a könyvben, azokról a filozófiai tézisekről írtam, amik leginkább bemutatják a világunk működését mozgató modelleket és törvényeit. Ezeket az eszméket sajnos a kereskedelmi érdek irányította globalizáció elhallgatni és titkolni próbálja az emberiség elől. A sorok között magyarázatot adok a mai világ problémáira, gazdasági válságára, annak végkifejletét előrevetítve.','2009.ZKI:1+61=62+1=63
