INSERT INTO "books" VALUES('',2,'','Kerekes_Gabor--Zwei_Jahrhunderte--FD.jpg','',0,1,0,0,41,'http://books.google.hu/books?printsec=frontcover&id=vD1O6DFl4F0C#v=onepage&q=&f=false',1,'',10,10,'','','','',50,100,0,NULL,10,4,2009,129,'Gábor Kerekes','Zwei Jahrhunderte der deutsch-ungarischen literarischen Kontakte. Interkulturelle Studien','978-963-9888-79-1',2,'','1','140x200 mm',140,'0',2490,1,'#LB5#',' Gábor Kerekes','http://www.konyvesbolt.online/spd/978-963-9888-79-1/Gabor-Kerekes-Zwei-Jahrhunderte-der-deutsch-ungari','','','','http://www.konyvesbolt.online/spd/978-963-9888-79-1/Gabor-Kerekes-Zwei-Jahrhunderte-der-deutsch-ungari','','Gabor-Kerekes','',3,2,1,7,4,1,0,'2008-11-0','2009-4-10','06-26-331-695','kegahu@yahoo.de','','','2009.ZKI:21+1=22',1230021087,1451380689,0);
INSERT INTO "books" VALUES('',0,'','Nemeth_Dezso--Uj_Minotaurusz--FD.jpg','','',1,0,13,3,'',1,'',40,65,'','','','','','',0,NULL,20,3,2009,130,'Németh Dezső','Új Minótaurosz','978-963-9888-81-4',2,'','2','A5',78,'0',1990,1,'#LA4+#LG10','Nemeth-Dezso','http://www.konyvesbolt.online/spd/978-963-9888-81-4/Nemeth-Dezso-Uj-Minotaurosz-Ad-Librum-2009','','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/egyeb_felnottirodalom/uj_minotaurosz','','','Nemeth_Dezso','',3,3,0,7,4,5,5,'Array-0-0','2009-3-20','(30)431-7837; 1211 Bp. Ady E. út 5. 3/10.','nemethdezso@windowslive.com','','Az „Új Minótaurosz” című kisregényemben feltaláltam azt a módszert, amellyel elkerülhetjük a halált. Feltaláltam az űrhajó nélküli űrutazást, és egy új elméletet világunk keletkezésére. A halál leküzdése: ez az elérhetetlennek tűnő vágy, talán a legszebb és legértékesebb értelme az ember életének. Életérzéseink tárolásával örökké élhetünk, de az ember mesterséges biológiai tenyésztése konfliktusokhoz vezet. Óriási dilemma elé kerülnek a kutatók, amikor az Isten tulajdonának tekintett életet teremtenek. Különösen akkor, amikor az esendő ember szexuális vágyainak kielégítésére használják a mesterséges lányokat, vagy katonai célokra hoznak létre biológiai lényeket.
INSERT INTO "books" VALUES('',0,'','Kovacs_Laszlo--Az_ehes_ornagy--FD.jpg','',0,1,0,0,3,'',1,'',40,65,'','',NULL,NULL,'',50,0,NULL,6,2,2009,131,'Kovács László','Az éhes őrnagy','978-963-9888-82-1',2,'','2','140x200 mm',60,'0',2100,1,'#LB2','Kovacs-Laszlo','http://www.konyvesbolt.online/spd/978-963-9888-82-1/Kovacs-Laszlo-Az-ehes-ornagy-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=78529&type=22&_v=Kovacs_Laszlo_Az_ehes_ornagy','','','http://www.konyvesbolt.online/spd/978-963-9888-82-1/Kovacs-Laszlo-Az-ehes-ornagy-Ad-Librum-2009','','Kovacs_Laszlo','',3,3,3,6,4,3,3,'2008-12-21','2009-2-6','1/220-1413, 1144 Budapest, Tihany út 42-44. fsz. 12.','laszlone.kovacs@chello.hu','','Kovács László 
INSERT INTO "books" VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,13,11,'http://books.google.hu/books?printsec=frontcover&id=aN_vOwbdSTIC#v=onepage&q=&f=false',0,'',10,40,'',50,5,274,500,500,2,NULL,4,2,2009,132,'Nácsa János','A Csontváry-kód, avagy nem esik messze a macska a fájától','978-963-9888-84-5',2,'','2','140x200 mm',240,'0',2490,2,'#A6 B:V LEZÁRT','Nacsa-Janos','','http://bookline.hu/product/home!execute.action?id=78155&type=22&_v=Nacsa_Janos_A_Csontvary_kod_avagy_nem_esik_messze_a_macska_a_fajatol','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/a_csontvary_kod_avagy_nem_esik_messze_a_macska_a_fajatol','','','Nacsa_Janos','',5,3,0,0,4,0,1,'2009-1-15','2009-2-4','Nácsa János, 30/292-4233, 7623 Pécs, Csend u. 20.','nacsajanos@freemail.hu','','Zseni vagy őrült? Csontváry Kosztka Tivadarral kapcsolatban nehéz ezt a kérdést megválaszolni, de talán kiegyezhetünk döntetlenben. Röpiratai, újságcikkei, valamint az önéletrajza legalább olyan rejtélyes, mint bármelyik festménye. Önmagát Raffaellónál sokkal többre tartotta, és volt annyira talányos, hogy Leonardo is elbújhatna mögötte Mona Lisástól, Utolsó vacsorástól, Sion-rendestől együtt. 
INSERT INTO "books" VALUES('',0,'','Boronkai_Dora--Tarsalgaselemzes--FD.jpg',254,'',1,0,37,35,'http://books.google.hu/books?printsec=frontcover&id=n8zPv3yFFfcC#v=onepage&q=&f=false',0,'',10,40,'',40,5,300,400,400,2,NULL,6,10,2009,133,'Boronkai Dóra','Bevezetés a társalgáselemzésbe','978-963-9888-89-0',2,'','2','A5',200,'0',2990,2,'#LB4, LGII#','http://adlibrum.hu/Boronkai-Dora/','http://www.konyvesbolt.online/spd/978-963-9888-89-0/Boronkai-Dora-Bevezetes-a-tarsalgaselemzesbe-Ad-Li','http://bookline.hu/product/home!execute.action?id=83695&type=22&_v=Boronkai_Dora_Bevezetes_a_tarsalgaselemzesbe','','http://www.fo.hu/hu/reszletes_kereso?kButton=1&h_gyorskereso=Boronkai&x=0&y=0&=Keresd','','','Boronkai-Dora','',3,3,0,7,4,5,0,'2009-8-31','2009-10-6','30/848-6445 (régi: 70/279-9889) Új cím: 7030 Paks, Tolnai u. 6/b.','boronkaidori@freemail.hu','Mitől válnak érthetővé a mindennapi társalgások összecsapott, hibás szerkezeteket tartalmazó, rögtönzött szövegfoszlányai?','Mitől válnak érthetővé a mindennapi társalgások összecsapott, hibás szerkezeteket tartalmazó, rögtönzött szövegfoszlányai? Miért nem akadályozzák meg a hibák és hibajavítások a spontán beszélgetések megértését, és hogyan segítik szerveződésüket? Milyen mentális folyamatok és interakciós szabályok lépnek működésbe a hétköznapi nyelvi tevékenység során? A fentiekhez hasonló kérdésekre választ keresve a szerző egy olyan tudományág bemutatására tesz kísérletet, amelynek átfogó ismertetése magyar nyelven eddig még nem jelent meg. Az első fejezetekben számba veszi a társalgáselemzés előzményeit, alapfogalmait, főbb kutatási területeit, majd bemutatja az elemzés módszertani lépéseit és alkalmazási lehetőségeit. A könyv a külföldi szakirodalom és a hazai empirikus kutatások eredményeit ötvözi, megállapításait saját gyűjtésű, beszélt nyelvi szövegkorpuszból származó példák segítségével támasztja alá. A szerző a Pécsi Tudományegyetem Illyés Gyula Főiskolai Karának adjunktusa, számos spontán nyelvhasználattal foglalkozó publikáció szerzője. Doktori disszertációját a társalgások szövegtani jellemzőiről írta kognitív nyelvészetből. A gazdag nyelvi példaanyaggal illusztrált könyv a témához kapcsolódó kutatómunkájának szintézise, amely hasznos módszertani segítséget nyújthat a spontán nyelvhasználat további empirikus vizsgálatához, hiánypótló összefoglaló és oktatási segédanyag lehet a felsőoktatásban, és ajánlható mindazoknak, akik többet szeretnének tudni a hétköznapi, spontán helyzetekben történő kommunikációról.','2011.11.02. Új cím: 7030 Paks, Tolnai u. 6/b.
INSERT INTO "books" VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,14,'',0,'',5,20,'',25,5,419,100,110,3,NULL,23,4,2009,134,'Tabacsik Ferenc','Az éjszaka szülötte','978-963-9888-95-1',2,'','2','A5',160,'0',2190,2,'LEZÁRT ->§466','Frank-Bauer','','http://bookline.hu/product/home!execute.action?id=80219&type=22&_v=Tabacsik_Ferenc_Az_ejszaka_szulotte','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/az_ejszaka_szulotte','','','Tabacsik_Ferenc','',5,3,1,7,4,1,1,'2009-1-0','2009-4-23','Tabacsik Ferenc, 2475 Kápolnásnyék, Balassa u. 4.','tabacsikferenc@citromail.hu','Létezik egy világ, amelyről csak kevesen tudnak az emberek közül. A Földön ma elhatalmasodott a bűn, és a sötétség az úr. De él közöttünk egy bátor hős, aki életét a gonosz elleni küzdelemre tette fel. Ez a férfi Frank Bauer, a különleges képességekkel bíró magánnyomozó.','Létezik egy világ, amelyről csak kevesen tudnak az emberek közül. Ez a világ itt van körülöttünk, de mégsem látjuk. Csak az igaz szívvel és tiszta tudattal rendelkező teremtmények előtt tárja fel kapuit. Egy másik dimenzió. 	
INSERT INTO "books" VALUES('',0,'','Kate_van_Dyke--A_latin_demon-FD.jpg',339,0,1,0,0,11,'http://books.google.hu/books?printsec=frontcover&id=wFYjqFa9xXgC#v=onepage&q=&f=false',1,'',10,40,'',50,5,350,500,500,2,NULL,24,4,2009,135,'Kate Van Dyke','A latin démon','978-963-9888-91-3',2,'','2','140x200 mm',284,'0',1990,2,'#LGIII, LGIV,LE2# D T:G B:V Tóth Katalin','Kate-van-Dyke','http://www.konyvesbolt.online/spd/978-963-9888-91-3/Kate-Van-Dyke-A-latin-demon-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=80218&type=22&_v=Van_Dyke_Kate_A_latin_demon','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/a_latin_demon','http://www.konyvesbolt.online/spd/978-963-9888-91-3/Kate-Van-Dyke-A-latin-demon-Ad-Librum-2009','','Kate_van_Dyke','',3,3,1,5,4,1,1,'2009-1-0','2009-4-24','Tóth Katalin,06-20-443-6324, 1119 Budapest, Etele út 24.','vadtigris.htk@gmail.com','A Csontgolyó szerzőjének új könyve!','Elvérzett. Valaki leütötte, aztán elvágta az ütőerét. Nem sokkal később méreg végez egy fiúval. A módszer ugyan más, de mindkét holttest mellett találnak egy-egy latin szentenciát. Ezen kívül annyi köztük a kapcsolat, hogy a római Colosseum mellett légiós jelmezben szórakoztatták a turistákat. Az első börtönből szabadult, zsarolták, és a drogpiacon próbált pénzhez jutni. A második makulátlan jellem volt, de talán látott valamit. Rio Mancini nyomozóra és társára vár a feladat, hogy elkapják a gyilkost, de akárhányszor vélik úgy, hogy közelebb jutottak a megoldáshoz, annyiszor derül ki, hogy tévedtek. Mancini életében ráadásul felbukkan a volt menyasszonya…','2009.ZKI:271
INSERT INTO "books" VALUES('',0,'','Nagy_Zoltan_Andras--Buncselekmenyek_szamitogepes_kornyezetben--FD.jpg','','',1,0,0,38,'http://books.google.hu/books?printsec=frontcover&id=uKULV9okcSIC#v=onepage&q=&f=false',1,'',5,20,'',25,5,615,100,110,3,NULL,12,10,2009,136,'Dr. Nagy Zoltán András','Bűncselekmények számítógépes környezetben','978-963-9888-92-0',2,'','2','A5',293,'0',2990,2,'#LA2 Dr. Nagy Zoltán András','Nagy-Zoltan-Andras','http://www.konyvesbolt.online/spd/978-963-9888-92-0/Dr--Nagy-Zoltan-Andras-Buncselekmenyek-szamitogepe','','','http://www.fo.hu/hu/konyv/gazdasag/kozgazdasag/buncselekmenyek_szamitogepes_kornyezetben','','','','',3,3,1,7,4,5,1,'2008-12-0','2009-10-12','Dr. Nagy Zoltán András, 7627 Pécs, Vadász u. 60/3., 06-203810458','drnagy.zoltan@chello.hu','','','2009.ZKI:37
INSERT INTO "books" VALUES('',0,'','','',0,0,0,12,22,'http://books.google.hu/books?printsec=frontcover&id=c9pXcGlpyt8C#v=onepage&q=&f=false',0,'',10,40,'',50,5,650,500,500,2,NULL,4,6,2009,137,'Aimen Klimmeron','Káma Púra - A gyönyörök városa','978-963-9888-94-4',2,'','2','A5',476,'0',3990,2,'#LD#  T:G Csibi István Levente','Kama-Pura','','http://bookline.hu/product/home!execute.action?id=81300&type=22&_v=Klimmeron_Aimen_Kama_Pura_A_gyonyorok_varosa','','','','','','',5,3,1,7,4,1,1,'2008-12-0','2009-6-4','Csibi István Levente, Sf. Georghe, jud. Covasna, Str. Várady József, nr. 72A, Bl. 1, ap. 14, Románia','klimmeron@yahoo.co.uk','Ezoterika, erotika','Regény művészetről, szerelemről, szexualitásról, két – egy jellegzetesen női és egy jellegzetesen férfi – szemszögből. Egy svéd zenészfiú és egy francia táncoslány párhuzamosan meséli kalandjait, szerelmi életének fontos állomásait, a gyerekkori nemi vágy első rezdüléseitől kezdve a tantrikus szerelem mély, szakrális dimenzióinak feltárulásáig.  Életútjuk, amely Közép-Kelet-Európában keresztezi egymást, külső és belső utazás is egyben: kemény megpróbáltatások egész sora, amely révén a két főhős saját lelkivilágának árnyoldalaival találja szemben magát, ugyanakkor olyan tapasztalatokban részesül, amelyek az élet dolgainak mélyebb megértéséhez vezetik őket.
INSERT INTO "books" VALUES('',0,'','','',0,0,0,0,0,'',1,'',10,40,'',40,5,280,300,300,3,NULL,30,9,2009,138,'Chris Chleone','Határok nélkül‭ ‬-‭ ‬Utazások a végtelenbe','',2,'','2','A5',100,'0',1990,2,'','Chris-Chleone','','','','','','','Chris_Chleone--Hatarok_nelkul','',4,3,1,4,4,1,1,'2008-12-28','2009-9-30','Bóné Krisztián','','','A kötetben szereplő írások a képzelet szülöttei. Mégis, lehetséges forgatókönyvei a valóságnak. A világ végtelen, határok nélküli, s a képzelet (vagy a valóság?) tölti ki e végtelen teret.
INSERT INTO "books" VALUES('',0,'','Olomlabu_Tonya--Allj_vagy_elaslak--FD.jpg','','',1,0,20,18,'',1,'',40,65,'','','','','',1000,0,NULL,19,2,2009,139,'Ólomlábú Tonya','Állj vagy eláslak! - szemelvények a lapátos alakulatok életéből','978-963-9888-85-2',2,'','2','148x200 mm',206,'0',2190,1,'#LD#  RB1c Ferwagner Antal T:G,B:V Ny:Mondat','Olomlabu-Tonya','http://www.konyvesbolt.online/spd/978-963-9888-85-2/Olomlabu-Tonya-Allj-vagy-elaslak---szemelvenyek-a-','','','http://www.fo.hu/hu/konyv/szepirodalom/memoar_eletrajz_interju/allj_vagy_elaslak_szemelvenyek_a_lapatos_alakulatok_eletebol','','','Olomlabu_Tonya--Allj_vagy_elaslak','Olomlabu_Tonya--Allj_vagy_elaslak',3,3,3,6,4,1,3,'2009-1-6','2009-2-19','Ferwagner Antal','antal.ferwagner@t-online.hu','','Te is ott voltál? Ha igen, akkor tudod, hogy mi az a lapátos alakulat; ha pedig nem volt benne részed, akkor most egy „élménnyel`` gazdagabb lehetsz. Ja! – nem is voltál katona? Csórikám, nem is tudod, mit vesztettél. Mi, akik részt vettünk ebben az állami pénzen szponzorált kalandban, mi tudjuk – két (gyengébbek másfél) évet pazaroltunk el az életünkből. Igaz, ezt nem vettük észre, mert a 70-es és a 80-as években még nem volt ilyen gyors a világ, a Czinege-korszak lassan csordogált a csámpásan kitaposott medrében. Két évet vesztegettünk el, de nem feleslegesen. Hihetetlen kalandokban volt részünk, amely felkészített minket az élet árnyas oldalának derűs elviselésére.
INSERT INTO "books" VALUES('',0,'','Kun_Attila--A_multinacionalis_vallalatok_szocialis_felelossege--FD.jpg',550,0,1,0,43,34,'',1,'',40,65,'','',5,351,'',500,0,NULL,16,6,2009,140,'Kun Attila','A multinacionális vállalatok szociális felelőssége - CSR-alapú önszabályozás kontra (munka)jogi szabályozás','978-963-9888-86-9',2,'','2','A5',312,'0',4500,1,'#LB2,LGIII-IV#   RG','Kun-Attila','http://www.konyvesbolt.online/spd/978-963-9888-86-9/Kun-Attila-A-multinacionalis-vallalatok-szocialis-','http://bookline.hu/product/home!execute.action?id=81677&type=22&_v=Kun_Attila_A_multinacionalis_vallalatok_szocialis_felelossege','','http://www.fo.hu/hu/konyv/gazdasag/kozgazdasag/a_multinacionalis_vallalatok_szocialis_felelossege_csr_alapu_onszabalyoza','http://www.konyvesbolt.online/spd/978-963-9888-86-9/Kun-Attila-A-multinacionalis-vallalatok-szocialis-','','','',3,3,0,7,2,0,0,'2009-4-1','2009-6-16','30/345-8032 - 2235 Mende, Dózsa Gy. út 77.','kunattila@freemail.hu','A piacelvű elváráson túli szociális felelősség taglalása a multik, a világszervezetek (ENSZ, OECD, EU) és a közpolitika szemszögéből.','``CSR - ugyanaz a fogalom sorsa, mint a demokrácia vagy a civilizáció kifejezéseké? Minél többet használjuk, annál kevesebbet tudunk róla, egyben annál többféle értelmezése létezik. Mi a CSR? A vállalatok jótékonykodása, mely valódi arcukat fedi el? Avagy a közjóért elkötelezett felelős vállalatvezetés? Aki ezt a könyvet elolvassa már nem ugyanúgy fog gondolkodni a világról, mint korábban.`` (Ligeti György, CSR szakértő, Kurt Lewin Alapítvány).
INSERT INTO "books" VALUES('',0,'','Atrox_Teuton--Az_elatkozott_grofsag--FD.jpg',526,'',1,0,0,13,'http://books.google.hu/books?printsec=frontcover&id=ZppUG9MtvxgC#v=onepage&q=&f=false',1,'',10,40,'',50,5,500,500,500,2,NULL,28,7,2009,141,'Atrox N. Teuton','Az elátkozott grófság','978-963-9888-97-5',2,'','2','148x210 mm',400,'0',3290,2,'#LB4,LGVI,LG23# #RB1 T:G B:V Szeder Norbert Attila','Atrox','http://www.konyvesbolt.online/spd/978-963-9888-97-5/Atrox-N--Teuton-Az-elatkozott-grofsag-Ad-Librum-20','http://bookline.hu/product/home!execute.action?id=82274&type=22&_v=Teuton_Atrox_N_Az_elatkozott_grofsag','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/az_elatkozott_grofsag','','','','',3,3,1,7,4,0,0,'2008-12-0','2009-7-28','Szeder Norbert Attila, 1203 Budapest, Ősz utca 20., 06-30-904-3465','atrox@inf.elte.hu','Nagyszabású fantasy regény.','Atanar a civilizációtól távol, egy gyors folyású, hegyi patak partján tér magához. Megdöbbenve tapasztalja, hogy emlékeit elvesztette, eddigi életéből semmire nem emlékszik. Ki ő? Honnan jött? Hová tart? A múlt felderítésére egyetlen esélye egy rövid levél, mely átázva kerül elő mellénye zsebéből. Ennek nyomán elindul, hogy felderítse múltját, ám hamarosan megtapasztalja, hogy ez nem olyan egyszerű dolog. Útja során számtalan ellenséget, akadályt kell leküzdenie, mert ez a világ veszélyes, és a gyengék nem sokáig élnek. Azonban értékes barátokra is szert tesz kalandozásai során. És közben egy percre sem felejti el célját: felkutatni elveszett múltját. A nyomok végül egy távoli grófságba vezetnek, ahol furcsa dolgok történnek…','2009.ZKI:10+220=230
INSERT INTO "books" VALUES('',0,'','Mary_Morgan--Selina--FD.jpg','',0,1,0,0,14,'',1,'',10,40,'',50,5,350,500,500,2,NULL,31,3,2009,142,'Mary Morgan','Selina, a vámpírboszorkány','978-963-9888-87-6',2,'','2','A5',320,'0',2990,2,'#LA4 425 gr. Balogh Orsolya','Mary-Morgan','http://www.konyvesbolt.online/spd/978-963-9888-87-6/Mary-Morgan-Selina-a-vampirboszorkany-Ad-Librum-20','','','http://www.fo.hu/hu/konyv/szepirodalom/ifjusagi_irodalom/regenyek/selina_a_vampirboszorkany','http://www.konyvesbolt.online/spd/978-963-9888-87-6/Mary-Morgan-Selina-a-vampirboszorkany-Ad-Librum-20','','Mary_Morgan--Selina','Mary_Morgan--Selina',3,3,1,7,4,1,1,'2008-12-0','2009-3-31','BALOGH ORSOLYA, 30/522-53-21, állandó: 1221 Budapest, Leányka u. 32. IX/58.; ideiglenes: 1225 BUDAPEST AKÓ U. 26.','morgan333@freemail.hu','Egy lány, aki tizennyolc éves koráig csak ember volt... majd egyszerre lett vámpír és boszorkány.','Biztos hogy csak ember vagy? 
INSERT INTO "books" VALUES('',0,'','Szoke_Eda--Tevelyges--FD.jpg','','',1,0,0,12,'',0,'',5,20,'',25,5,402,100,107,3,NULL,19,2,2009,143,'Szőke Eda','Tévelygés. Egy hűtlen feleség magyarázkodása','978-963-9888-88-3',2,'','2','A5',148,'0',2390,2,'#LB3','Eda','http://www.konyvesbolt.online/spd/978-963-9888-88-3/Szoke-Eda-Tevelyges--Egy-hutlen-feleseg-magyarazko','','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/tevelyges_egy_hutlen_feleseg_magyarazkodasa','','','','',3,3,1,6,4,0,1,'2008-12-0','2009-2-19','Lévainé Udvari Anna, 70/503-74-93, 7400 Kaposvár, Béke u. 81. fszt. 1.','udvarianna@gmail.com','','Ha a házasságod már nem tesz boldoggá, könnyen besétálhat az életedbe Valaki. A titkos találkák varázsa által egy szikra is igazi tűzvésszé nőhet, így az a Valaki életed legszebb élményeivel ajándékozhat meg. De lehetsz-e boldog új szerelmeddel olyan áron, hogy gyermekedet boldogtalanná teszed? Valóban mindent megtettél a házasságod megmentéséért? Ha ez a kérdés bizonytalanságot kelt benned, nem biztos, hogy jó úton jársz. Helyre lehet-e hozni egy már menthetetlennek tűnő házasságot? Ez a történet bizonyítja, hogy igen. A jó házassághoz nem feltétlenül szerelemre van szükség. A szeretet, a tisztelet és az egymásra figyelés csodát tehet. Csak igazán akarni kell…','2009.ZKI:8+30=38+1=39; G: OK!
INSERT INTO "books" VALUES('',0,'','Kakuk_Matyas--Szkita-magyar--FD.jpg','','',1,0,35,39,'',0,'',40,65,'','','','','',100,0,NULL,2,4,2009,144,'Kakuk Mátyás','Szkíta-magyar nyelvhasonlítás','978-963-06-6658-9',1,'','2','A5',230,'0',2490,1,'#LA5','Kakuk-Matyas','http://www.konyvesbolt.online/spd/978-963-06-6658-9/Kakuk-Matyas-Szkita-magyar-nyelvhasonlitas-2009','','','http://www.fo.hu/hu/konyv/tovabbi_konyveink/szkita_magyar_nyelvhasonlitas','','','Kakuk_Matyas','',3,3,1,7,4,5,5,'2008-12-0','2009-4-2','','kakukm@invitel.hu','','„Dúl leányi, a legszebbek,
INSERT INTO "books" VALUES('',0,'','Jade_Dorado--Erinthetetlen--FD.jpg',447,'',1,0,11,12,'',1,'',10,40,'',25,5,783,100,100,3,NULL,28,5,2009,145,'Jade Dorado','Érinthetetlen','978-963-9888-96-8',2,'','2','A5',390,'0',3490,2,'#LB2+LG27# Péter Anita','Jade-Dorado','http://www.konyvesbolt.online/spd/978-963-9888-96-8/Jade-Dorado-Erinthetetlen-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=81298&type=22&_v=Dorado_Jade_Erinthetetlen','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/erinthetetlen','','','Jade_Dorado--Erinthetetlen','',3,3,1,7,4,5,1,'2009-1-16','2009-5-28','Péter Anita, 8132 Lepsény, Zengő  Dülő 1429/2. 06 70 317 2134','flycomp@gmail.com','Fordulatos kalandregény egzotikus helyszíneken.','Zsarad elnevette magát, és elengedte a kezét. Titó ebben a pillanatban már nagyon féltette az életét, nem is tudott figyelni a férfira, akire ha ránézett volna, látta volna, hogy nem akarja bántani és kényszeríteni semmire. Futtában leráncigálta magáról a csadort, mert zavarta a kilátásban és minden lépésében. Ekkor közvetlen mellette egy motoros állt meg, készült kitámasztani a motort a teret keretező vaskorlátnak. Titó azonnal átugrotta a korlátot, ezzel fellökve a fiatal fiút, aki a motor tulajdonosa volt, és döbbenten állt a jelenet előtt. Gyorsan berúgta és végigsöpört vele egy hosszú, keskeny utcán, ahol a köveket fényesre járták az emberek, és faltól-falig csupán két méter széles. Túl sokat kellett kerülgetnie az elélépőket, és félt, hogy Zsarad karja eléri. A sarokról egy pillanatra visszanézett, hogy Zsarad hol jár a nyomában, de az nem mozdult, hanem a kávézó teraszán állt zsebre tett kézzel, és őt nézte. Elengedte? Meg mert volna esküdni rá, hogy mosolyog.','2009.ZKI:42+1=43
INSERT INTO "books" VALUES('',0,'','Redenczki_Maria--Turelemfa--FD.jpg','','',1,0,20,17,'',1,'',40,65,'','','','',100,110,0,NULL,10,4,2009,146,'Redenczki Mária','Türelemfa - avagy nevel, vagy nevelem a családom?','978-963-9888-98-2',2,'','2','A5',52,'0',1990,1,'Minden saját példányt visszakapott a szerző. Tóth Miklósné','Redenczki-Maria','','http://bookline.hu/product/home!execute.action?id=79975&type=22&_v=Redenczki_Maria_Turelemfa_avagy_nevel_vagy_nevelem_a_csaladom_','','http://www.fo.hu/hu/konyv/tovabbi_konyveink/turelemfa_avagy_nevel_vagy_nevelem_a_csaladom','','','','',5,3,0,7,4,0,0,'Array-0-0','2009-4-10','Tóth Miklósné 20/440-8700 Cím: 6000 Kecskemét. Kodolányi János utca 15. II/4.','tejbegriz@vipmail.hu','﻿Azoknak, akik okulni szeretnének egy fiatal, lelkes családanya nehézségeiből. Azoknak, akik röhögni szeretnének egy fiatal, lelkes családanya nehézségein.','﻿Azoknak, akik okulni szeretnének egy fiatal, lelkes családanya nehézségeiből.
INSERT INTO "books" VALUES('',0,'','Fust_Antal--Koronas_hegyek--FD.jpg',216,'',1,0,0,8,'',1,'',40,60,'','',NULL,NULL,'','',0,NULL,3,11,2010,147,'Füst Antal','Koronás hegyek – A Zagyva-völgyi várak regénye','978-615-5014-61-1',2,'','3','130x200 mm',192,'0',2490,1,'#LC3,LGV#  §362 folytatása, K:K,B:V,T:G','Fust-Antal','http://www.konyvesbolt.online/spd/978-615-5014-61-1/Fust-Antal-Koronas-hegyek-A-Zagyva-volgyi-varak-re','','','','','','','',3,0,0,0,0,0,0,'Array-0-0','2010-11-3','Dr. Füst Antal, 30/353-2766, 1142 Budapest, Nezsider park 2.','antalfust@gmail.com','Történelmi rege a török idők várairól.','A Zagyva-völgyi várak megmaradt kövei ma is valami különleges erőt sugároznak. Ostromágyúk által szaggatott falaikkal, felhőkbe törő csonka lakótornyaikkal a magyarság nagy próbatételeit idézik, példát mutatnak az utókornak, vitézségből és helytállásból. A késői utódok borzongva mesélik a védők hőstetteit, menekülő alagutakról, nagy szerelmekről és még nagyobb tragédiákról suttognak. A kövek pedig továbbra is féltékenyen őrzik a titkokat.
