INSERT INTO "books" VALUES('',0,'','Sebestyen_Adam--A_bukovinai_szekelyseg--FD.jpg',721,'',1,0,0,37,'',0,'',0,0,'','',NULL,NULL,'',500,0,NULL,25,5,2009,159,'Sebestyén Ádám','A bukovinai székelység tegnap és ma','978-963-9934-11-5',2,'','2','B5',414,'0',2990,3,'#LC,LGsalgó#','Sebestyen-Adam','http://www.konyvesbolt.online/spd/978-963-9934-11-5/Sebestyen-Adam-A-bukovinai-szekelyseg-tegnap-es-ma','http://bookline.hu/product/home!execute.action?id=81294&type=22&_v=Sebestyen_Adam_A_bukovinai_szekelyseg_tegnap_es_ma','','http://www.fo.hu/hu/konyv/ismeretterjeszto_1/tarsadalomtudomany/a_bukovinai_szekelyseg_tegnap_es_ma','','','','',3,3,1,9,4,5,5,'2009-3-0','2009-5-25','Sebestyén Imre Dezső, 74/674-994,7100 Szekszárd, Csalogány u. 18., ','','','Álljon itt egy idézet Sebestyén Ádám 1996. január 24-i teme­tésén dr. Andrásfalvy Bertalannak, a Magyar Néprajzi Társaság elnökének beszédéből: ``Sebestyén Ádám azoknak a példaképe lehet, akiket a sors nem kímélt és mégis saját erejükből, és isten segedelmével ennek a népnek nagy­jaivá lettek. Igen... ezek tartják meg a népet, akik felmutatják értékét és kin­csét, áldozatos munkával összegyűjtik mindazt, ami minket magyarrá tesz... S ezeken a műveken, az ő munkásságán fogunk tanulni, fogjuk tovább élni a nekünk kijelölt életet...``','3 pld. több mint 2 kg
INSERT INTO "books" VALUES('',0,'','Sebestyen_Adam--Marika_mesel_I--FD.jpg',695,'',1,0,0,37,'',0,'','','','','',NULL,NULL,'',210,0,NULL,25,5,2009,160,'Sebestyén Ádám','Bukovinai székely népmesék I. - Márika meséi','978-963-9934-12-2',2,'','2','B5',608,'0',2990,3,'#LC#','Sebestyen-Adam','http://www.konyvesbolt.online/spd/978-963-9934-12-2/Sebestyen-Adam-Bukovinai-szekely-nepmesek-I----Mar','','','','','','','',3,3,1,9,4,0,0,'2009-3-0','2009-5-25','Sebestyén Imre Dezső, 74/674-994,7100 Szekszárd, Csalogány u. 18., ','','Sebestyén Ádám, a bukovinai székelyek néprajzkutatója ebben a kötetben 90 gyöngyszemet gyűjtött össze.','Sebestyén Ádám a bukovinai székely telepesek története, népdalai és földművelése után népmeséik összegyűjtéséhez és a ma élő, illetve a kö­zelmúltban elhunyt kiemelkedő mese­mondók bemutatásához fogott. A bukovinai székelyektől gyűjtött népmeséket összesen 1782 oldalon négy kötetben Bukovinai székely népmesék I–IV. címmel a Tolna megyei Könyvtár adta ki 23–30 évvel ezelőtt. 
