INSERT INTO "books" VALUES('',0,'','Ferenczi_Krisztina--Tunodes_egy_gondolatsoron--FD.jpg','','',1,0,0,2,'',1,'',8,30,'',125,5,230,500,500,4,NULL,20,4,2009,162,'Ferenczi Krisztina','Tűnődés egy gondolatsoron - versek','978-963-9934-07-8',2,'','2','A5',126,'0',2390,2,'#LA3,LG32,LGrégi polc#','Ferenczi-Krisztina','http://www.konyvesbolt.online/spd/978-963-9934-07-8/Ferenczi-Krisztina-Tunodes-egy-gondolatsoron---ver','http://bookline.hu/product/home!execute.action?id=79974&type=22&_v=Ferenczi_Krisztina_Tunodes_egy_gondolatsoron_versek','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/vers_drama/tunodes_egy_gondolatsoron_versek','','','','',3,3,0,7,4,1,1,'2009-3-0','2009-4-20','Ferenczy Krisztina; 30/751-0495; Tardona, Dózya Gy. út 4.','jfkrisztina@citromail.hu','','Sok magányos éji óra szülöttei ezek a versek. Csillagokat számlálva kémleltem az éjszakai eget, mint aki keres valamit. Mit kerestem? Önmagam... Vágyakból, álmokból, káoszból igyekeztem csillagképeket építeni;  megfejteni a bennem áradó lét minden atomját; kiismerni a szelet, mi arcomhoz ér; az éji csendből dallamot szűrni; csillagfényeket olvasztani homlokom mögé... 
INSERT INTO "books" VALUES('',0,'','',186,0,0,0,26,34,'http://books.google.hu/books?printsec=frontcover&id=4-P_YKwFY7YC#v=onepage&q=&f=false',0,'',10,40,'Hasznos ismeretek és tanácsok ügyfeleknek és ügyféljelölteknek az életbiztosításokról és az életbiztosításokon keresztül történő befektetésekről.',250,5,160,1000,1000,4,NULL,30,4,2009,163,'Varga Géza','Menj biztosra! (Olvasókönyv biztosítósoknak és ügyfeleiknek)','978-963-9888-30-2',2,'','2','A5',128,'0',2490,2,'LEZÁRT ->§440','Menj-biztosra','','http://bookline.hu/product/home!execute.action?id=80373&type=22&_v=Varga_Geza_Menj_biztosra_Olvasokonyv_biztositosoknak_es_ugyfeleiknek','','http://www.fo.hu/hu/konyv/gazdasag/kozgazdasag/menj_biztosra_olvasokonyv_biztositosoknak_es_ugyfeleiknek','','','Varga-Geza--Menj_biztosra','',5,3,1,7,4,0,1,'2009-4-24','2009-4-30','Dr. Varga Géza, 70/454-7741, 3580 Tiszaújváros, Babits M. u. 2.','menjbiztosra@gmail.com','','A könyv szerzője - közgazdász képzettségű biztosítási üzletkötő - átvilágította a biztosítások világát, és bemutatja, hogy hogyan látja azt egyszerre belülről és kívülről is. Hasznos ismereteket és tanácsokat ad ügyfeleknek és ügyféljelölteknek az életbiztosításokról és az életbiztosításokon keresztül történő befektetésekről. Rávilágít néhány, a biztosítók működésével és a biztosítások értékesítésével kapcsolatos hatékonysági problémára, és megértő empátiával firtatja a potenciális ügyfelek különböző attitűdjeit és annak okait. A szakmailag igényes tartalmat néhány színes, érzelemben gazdag olvasmány egészíti ki.
INSERT INTO "books" VALUES('',0,'','Sunny_McCormack--Urvandorok--FD.jpg','','',1,0,16,13,'',0,'',5,20,'',25,5,593,100,110,3,NULL,23,4,2009,164,'Sunny McCormack','Űrvándorok','978-963-9934-10-8',2,'','2','A5',284,'0',2990,2,'#LB3 Pokkné Borza Judit','Sunny-McCormack','http://www.konyvesbolt.online/spd/978-963-9934-10-8/Sunny-McCormack-Urvandorok-Ad-Librum-2009','','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/urvandorok','','','','',3,3,1,9,4,0,1,'2009-3-0','2009-4-23','Pokkné Borza Judit, 20/3494826, 1181 Budapest, Bezerédi u. 7.','borzajuci@freemail.hu','','Mi történik, ha egy ritka természeti jelenség során egy csapatnyi kamasz egy másik dimenzióból érkező űrhajón találja magát? És miként reagálnak, ha kiderül, nem tudnak hazajutni innen?
INSERT INTO "books" VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,3,'',0,'',6,20,'',75,5,225,300,300,4,NULL,26,6,2009,165,'Horváth Szilárd','Dögkút','978-963-9888-31-9',2,'','2','A5',120,'0',1990,2,'#B3 LEZÁRVA->§448','Horvath-Szilard','','http://bookline.hu/product/home!execute.action?id=82025&type=22&_v=Horvath_Szilard_Dogkut','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/dogkut','','','','',5,3,1,7,4,5,1,'2009-3-0','2009-6-26','06204746478, Bp. 1203 Kinizsi u. 16. fszt. 1.','hszilard76@gmail.com','','Horváth Szilárd a Miskolci Egyetemen végzett, szociológia szakon. Első írói próbálkozásában, mely a Dögkút címet kapta, novelláiban és drámájában keresi az emberi viselkedés alapját. Megfogalmazásaiban elfogultságról, életérzésekről tesz tanúbizonyságot, az emberi élet kuszaságát fejtegeti, miközben az olvasó saját érzelmeit ismerheti fel; töprengések, megválaszolatlan kérdések sorozata segíti felszínre, hogy az ismeretlenségtől a megismerés felé haladva a szerző mindenek kiindulópontját a szerelemben és a szenvedélyben azonosítja.','A maradék példányok számlázása 2011. februárjában a szeptemberi 1690 Ft-os postaköltséggel együtt.
INSERT INTO "books" VALUES('',0,'','Vasi_Szabo_Janos--Csillagpuszta--FD.jpg','',0,1,0,0,13,'http://books.google.hu/books?printsec=frontcover&id=-fSxn4GFeWIC#v=onepage&q=&f=false',1,'',45,65,'','',NULL,NULL,'',100,0,NULL,28,5,2009,166,'Vasi Szabó János','Csillagpuszta','978-963-9888-10-4',2,'','2','A5',72,'0',1690,1,'#LB5,LG7#','Vasi-Szabo-Janos','http://www.konyvesbolt.online/spd/978-963-9888-10-4/Vasi-Szabo-Janos-Csillagpuszta-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=81297&type=22&_v=Vasi_Szabo_Janos_Csillagpuszta','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/csillagpuszta','http://www.konyvesbolt.online/spd/978-963-9888-10-4/Vasi-Szabo-Janos-Csillagpuszta-Ad-Librum-2009','','','',3,3,0,7,4,0,0,'2009-3-0','2009-5-28','Vasi Szabó János, 94/711-108, 9762 Tanakajd, Kossuth L. u. 26.','vasi.szabo.janos@gmail.com','A Világállamban játszódó disztópiák és egyéb történetek.','Az első két történet a Világállamban játszódó disztópia. A  Haszontalan mágia főszereplője a szürke kishivatalnokként élő Jim Scone: kezébe kerül egy ősrégi recept. A vegyület felszabadítja az ember mentális képességeit. Scone képes lett a múltba pillantani. Így kiderítette, hogy ki erőszakolta meg brutálisan a komputerosztály csinos, fiatal alkalmazottját, aki emiatt öngyilkos lett. Ám hiába a különleges képesség, a nyomozók őt tartják tettesnek és elmegyógyintézetbe csukják.
INSERT INTO "books" VALUES('',0,'','Kormendi_Janos--Utolso_figyelmeztetes--FD.jpg',252,'',1,0,3,20,'',0,'',0,0,'','',NULL,NULL,'',5000,0,NULL,20,5,2009,167,'Körmendi János','Utolsó figyelmeztetés','978-963-9888-11-1',2,'','2','148x210 mm',168,'0',1990,3,'#LC3,LGI,LGV, LGrégi salgó,LG 27,27/a#','','http://www.konyvesbolt.online/spd/978-963-9888-11-1/Kormendi-Janos-Utolso-figyelmeztetes-Ad-Librum-200','','','http://www.fo.hu/hu/konyv/szepirodalom/memoar_eletrajz_interju/utolso_figyelmeztetes','','','','',3,3,3,7,0,0,1,'2009-3-0','2009-5-20','Körmendi Gabriella, 1022 Budapest, Alsótörökvész út 8., 30/9924-955, ','kgabcsi@chello.hu','A híres komikus halála előtt saját kezűleg összeállított könyve teli szórakoztató történetekkel színészekről és az élet furcsaságairól.','„A bohóc, ha meg is hal: azonnal föltámad. Elterül – és máris játszik tovább. (…) Körmendi János egyszemélyes színház volt. Bölcs és rendkívül vidám színház.”
