INSERT INTO "books" VALUES('',0,'','Petrozsenyi_Nagy_Pal.-Turos_puliszka--FD.jpg','','',1,0,0,3,'',1,'',45,65,'','',NULL,NULL,'',100,0,NULL,28,5,2009,169,'Petrozsényi Nagy Pál','Túrós puliszka','978-963-9934-13-9',2,'','2','140x200 mm',334,'0',2990,1,'#LA6,LGIII#','Nagy-Pal','http://www.konyvesbolt.online/spd/978-963-9934-13-9/Petrozsenyi-Nagy-Pal-Turos-puliszka-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=81302&type=22&_v=Petrozsenyi_Nagy_Pal_Turos_puliszka','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/turos_puliszka','','','','',3,2,0,7,4,0,0,'2009-3-0','2009-5-28','Nagy Pál, 06/76/41 30 35, Kecskemét, Puskás Tivadar 13.','gyanlap@hotmail.com','Cselekményes, fordulópontokban gazdag meseszövés, reális élethelyzetek, elgondolkodtató csattanók.','Cselekményes, fordulópontokban gazdag meseszövés, reális élethelyzetek, elgondolkodtató csattanók. Íme, néhány lényeges sajátosság, ami az erdélyi származású Petrozsényi Nagy Pál írásait jellemzi. Stílusa egyszerű, teljesen sallangmentes, így persze nincsenek benne sem sziporkázó stílusbravúrok, sem meghökkentő képek, gondolattársítások, melyek jelenkori irodalmunkban oly buján tenyésznek. Hogy emiatt már nem is korszerű? Bizonyos vonatkozásban valóban nem, de olyan fontos ez? Jelen és múlt, Magyarország, Erdély: két kor, két világ. Vajon vannak-e bennük közös érintkező pontok is? Mindezt bárki azonnal megtapasztalhatja, és ki tudja, talán önmagára is rábukkan, amint megízleli a Túrós puliszkát.','Új email: gyanlap@hotmail.com (2012-12-14, Régi: palnagy4@gmail.com)
INSERT INTO "books" VALUES('',0,'','','','',1,0,0,2,'',0,'','','','','',NULL,NULL,'',102,0,NULL,30,4,2009,170,'Dr. Sándorné Manyika','Örök szerelem','978-963-06-7064-7',1,'','2','A5',110,'0','',1,'#LB6#','','http://www.konyvesbolt.online/Dr--Sandorne-Manyika-Orok-szerelem','','','','','','','',3,2,1,9,4,5,3,'2009-4-7','2009-4-30','06-20-99-26-867; 9000? Győr, Szent István út 14/A.','angel8_anita@freemail.hu','A költőnő harmadik kötetével - főként szerelmes versekkel és gondolatokkal - szeretne kedveskedni az olvasóinak.','','Bemutatópl.: 1db',NULL,1460712895,0);
