INSERT INTO "books" VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,4,'',0,'',5,20,'',75,5,160,300,300,4,NULL,10,7,2009,183,'Góczi Noémi','Az élet árnyékában','978-963-9934-16-0',2,'','2','A5',60,'0',1990,2,'LEZÁRVA ->§429','Goczi-Noemi','','http://bookline.hu/product/home!execute.action?id=82023&type=22&_v=Goczi_Noemi_Az_elet_arnyekaban','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/az_elet_arnyekaban','','','','',5,3,0,7,4,0,0,'2009-6-0','2009-7-10','7145 Sárpilis, Dózsa u. 18. Tel.: 20/389-2201','nonyka90@freemail.hu','','A könyv, amelyet a kedves Olvasó a kezében tart, több nem mindennapi témát dolgoz fel történetszerűen. Ezek: skizofrénia, gyermeki félelmek, kéjgyilkosság – egyre inkább társadalmunk hozadékává válnak. Nem mindannyiunknak alakul ki közvetlen kapcsolata ezekkel a dolgokkal, de egyre többen vagyunk kénytelenek közvetetten találkozni velük újságok, TV-s közvetítések által, ezért érdemes és kell is foglalkoznunk velük, ha csak addig is, míg ezt a néhány rövid novellát végigolvassuk.
