INSERT INTO "books" VALUES('',0,'','Balas_Denes--A_tavirotol_a_radioig--FD.jpg',436,'',1,0,31,39,'http://books.google.hu/books?printsec=frontcover&id=20fRzs0Nns8C#v=onepage&q=&f=false',0,'',5,20,'',75,NULL,NULL,300,300,4,NULL,5,11,2009,187,'Balás B. Dénes','A távírótól a rádióig - A rádiótechnika története az 1800-as évektől a II. világháborúig','978-963-9934-19-1',2,'','2','A5',344,'0',2990,2,'#LB7#','radiotechnika-tortenet','http://www.konyvesbolt.online/spd/978-963-9934-19-1/Balas-B--Denes-A-tavirotol-a-radioig---A-radiotech','http://bookline.hu/product/home!execute.action?id=84667&type=22&_v=Balas_B_Denes_A_tavirotol_a_radioig','','','','','','',3,3,0,7,4,5,0,'2009-6-18','2009-11-5','Balás Dénes, 6090 Kunszentmiklós, Rákóczi u. 14. T.: 30/687-4277','bbdenes@freemail.hu','Egy legendás korszak – Morse távírójától (1837) a tranzisztor születéséig (1948) –, benne olyen híres és vitatott talányokkal, mint Marconi – Popov elsőbbsége, a Titanic és SOS legendája, Poulsen- és Ívlámpaadók.','A szerző, Balás B. Dénes 1958-ban végzett a Puskás Tivadar Távközlési Technikumban. Mint lelkes rádióamatőr QSO-zott az iskola első adóján, ezáltal nemcsak rádiótechnikus lett, hanem sejtjeibe ivódott a rádiós emlékek szeretete is. Bejárta Európa híresebb rádiótörténeti múzeumait és évente egy-egy cikkben publikálta az ott látottakat. Tagja volt 2006-ban az első magyar szikratávíró kísérlet 100. évfordulója tiszteletére újra megtett „Fiume – Ancona” adriai hajóútnak, amelyet sajnos már nem az „Előre” postahajón tehettünk meg. Több cikk íródott, sőt tudományos konferenciát is tartottunk a centenárium kapcsán.
INSERT INTO "books" VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,11,'',0,'',5,20,'',75,5,220,300,310,4,NULL,28,9,2009,188,'Salga Attila','A mátészalkai kalandor regényes története - Intézd úgy, hogy önszántukból adják!','978-963-9934-20-7',2,'','2','A5',126,'0',1990,2,'LEZÁRT ->§366','Salga-Attila','','http://bookline.hu/product/home!execute.action?id=83693&type=22&_v=Salga_Attila_A_mateszalkai_kalandor_regenyes_tortenete','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/a_mateszalkai_kalandor_regenyes_tortenete_intezd_ugyhogy_onszantukbol_ad','','','','',5,3,0,7,4,5,0,'2009-6-0','2009-9-28','4024 Debrecen, Batthyány u. 11/c. T.: 30/295-1969, 52/411-338','salga1@t-online.hu','','Strassnoff Ignác (1868-1933) rögtönzött szerepeket játszó zseniális kalandor volt. Rászedte a detektívfőnököt, behízelegte magát a gazdag szépasszonyoknál, ékszereikkel pedig angolosan távozott. A kaszinóban nem játszott, mégis nyert, nem létező ökörcsordát adott el, huszártiszti egyenruhájában mindenkit levett a lábáról. A fergetegesen jó színész kasszasikert aratott. Kár, hogy minden teátrum kicsinek bizonyult számára, így kénytelen volt az élet színpadán fellépni. Ezért a rendező-bírák „pályája” során több mint húsz év fegyházban játszódó szerepre ítélték. Magyarországon tizennyolc, külföldön tíz alkalommal „díjazták”.
INSERT INTO "books" VALUES('',0,'','Palicz_Judit--Tukrom--FD.jpg','','',1,0,0,2,'',1,'',40,70,'','',NULL,NULL,1000,1000,0,NULL,12,8,2009,189,'Palicz Judit','Tükröm','978-963-9888-59-3',2,'','2','A5','72+6','0',1490,1,'#LA3','Palicz-Judit','http://www.konyvesbolt.online/spd/978-963-9888-59-3/Palicz-Judit-Tukrom-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=82366&type=22&_v=Palicz_Judit_Tukrom','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/vers_drama/tukrom','','','','',3,3,0,9,4,5,0,'2009-6-0','2009-8-12','Kemex Kft., 30/5838-620','keme@enternet.hu','Nem egy hagyományos értelemben vett verseskötetet tartasz a kezedben, sokkal inkább az életemnek egy különösen fontos szeletét, amire ma már elfogadással, nyugalommal tudok emlékezni. 
INSERT INTO "books" VALUES('',0,'','Szinay_Balazs--FD.jpg','','',1,1,0,2,'',1,1481,10,'','','',5,400,'','',0,NULL,1,10,2009,190,'Szinay Balázs','Parampara (Válogatott versek 2001-2004)','978-963-9934-21-4',2,'','2','A5',228,'0',2490,5,'#LA3','Szinay-Balazs','www.konyvesbolt.online/spd/978-963-9934-21-4/Szinay-Balazs-Parampara-Valogatott-versek-2001-200','','','','','','Szinay-Balazs','',3,3,0,9,4,5,2,'2009-7-0','2009-10-1','1104 Bp., Harmat u. 154. IX/39. T.: 70/228-7888','szinba@gmail.com','','``Szóval…mi a lélek? Az, hogy vagyunk. Amikor szeretünk valakit, azt szeretjük, hogy van. Miről szól a szeretet? Arról, hogy szeretjük a másik lelkét. Milyen a másik lelke? Ragyogó. Mi a ragyogás? Nem a másik jó vagy rossz tulajdonságai, hanem a fény, ami a lelkéből árad. Tehát, mikor azt mondjuk valakire, hogy szeretjük őt, nem arról beszélünk, hogy szeretjük azt, hogy ilyen vagy olyan, hanem szeretjük, hogy van, szeretjük a lelkét, és átéljük annak ragyogását. Ilyenkor a rossz dolgok is szépnek tűnnek, mivel átitatjuk énünket a másik fényével, és nem tulajdonságainak viselkedésünkre ható felhangjaival azonosulunk. Szerelem vagy szeretet?! Mi különbség van a kettő között, mindkettő fényből táplálkozik? Mindkettő a lélek fényére reagál. Amikor a másik azt mondja, hogy már nem szeret minket, az azt jelenti, hogy elvesztette a kapcsolatot lelkünk ragyogásával, nem pedig azt, hogy a lelkünk nem ragyog. Mindenki lelkét ugyanaz a fény ragyogja be, de ez a fény nem birtokolható, csak időnként megosztjuk valakivel. Hogy hogyan? A lelkünk fényét lehet barátként, társként, szerelmesként, szülőként, testvérként is használni. Csak meg kell tanulnunk ezzel bánni. Ennyi az egész. Figyeljen mindenki  a fényre és törekedjen a boldogság felé. Boldognak lenni annyi, mint kapcsolatba kerülni a lélek fényével. Racionalitás azt jelenti, látni a másik hibáit is, de nem az orra alá dörgölni, figyelni rá és nem bántani. Emocionalitás, elfogadni és szeretni őt így is, rávilágítva a jóra. Ebből állnak az emberi kapcsolatok és a szeretet v. szerelem így kitarthat egy életen át.``','2009.ZKI:11+1=12 Nem kér fogyásjelentést
INSERT INTO "books" VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,16,'',0,'',8,30,'',125,5,300,500,500,4,NULL,19,10,2009,191,'Villányi Rózsa','Barátom, Cvek Edli','978-963-9934-23-8',2,'','2','A5',52,'0',1990,2,'#A2 LEZÁRVA','Villanyi-Rozsa','','http://bookline.hu/product/home!execute.action?id=84031&type=22&_v=Villanyi_Rozsa_Baratom_Cvek_Edli','','http://www.fo.hu/hu/konyv/szepirodalom/gyerekirodalom/mesek/baratom_cvek_edli','','','Villanyi-Rozsa','',5,3,0,7,4,5,0,'2009-7-2','2009-10-19','7634 Pécs, Szúnyog dűlő 1. T.: 30/403-1286','villanyi.rozsa@gmail.com','','„Elárulok egy titkot. A halhatatlanság titkát. Ha szülőként, nagyszülőként mesélünk gyermekeinknek, akkor ők arra egy életen át emlékezni fognak, és az emlékünket a mesékkel együtt generációknak adják tovább. Kérem, higgyenek nekem, anyukaként és gyermekkönyvtárosként tudom, hogy így van. A meghitt percekhez szeretettel nyújtom át Cvek Edli és Dozó történetét.”
