INSERT INTO "books" VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,2,'',1,'',5,20,'',75,NULL,NULL,300,300,5,NULL,3,11,2009,211,'Liz Bet','Végre az enyém...','978-963-9934-39-9',2,'','2','A5',80,'0',1690,2,'LEZÁRT ->§442 Kiss-Hegyi Erzsébet','Liz-Bet','','http://bookline.hu/product/home!execute.action?id=84491&type=22&_v=Bet_Liz_Vegre_az_enyem_','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/vegre_az_enyem','','','','',5,3,0,7,4,5,1,'2009-9-0','2009-11-3','Kiss-Hegyi Erzsébet, 30/463-5482, 3300 Eger, Vízimolnár u. 8. 3/9.','lisandra@freemail.hu','','Mary, a csinos ingatlanközvetítő mélységesen csalódott férjében. A válás után egyedül él, nem is akar hallani férfiakról. Barátnője unszolására végül mégis felad egy hirdetést egy társkereső irodánál.
