INSERT INTO "books" VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,8,'http://books.google.hu/books?printsec=frontcover&id=YOVK11iiVBMC#v=onepage&q=&f=false',0,'',0,0,'',75,NULL,NULL,300,300,2,NULL,20,11,2009,218,'Endridi Skalli','Amit Ódin súgott','978-963-9934-45-0',2,'','2','140x200 mm',400,'0',2990,2,'LEZÁRVA -> §453 #C T:G,B:szerző Dr. Kolozs Balázs.','Skalli','','http://bookline.hu/product/home!execute.action?id=85372&type=22&_v=Skalli_Endridi_Amit_Odin_sugott','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/amit_odin_sugott','','','','Endridi_Skalli',5,3,0,7,4,5,3,'2009-9-28','2009-11-20','Dr. Kolozs Balázs, 30/241-7164, 1143 Budapest, Hungária krt. 97. IV/1.','kolozsbalazs@gmail.com','','A XIV. századi Grönland világtól elzárt skandináv településein a vikingek kora még nem ért véget. A tűzhelyek parazsa mellett régi-új mesék kapnak szárnyra elfeledett istenekről, valamint pogány regékből ismert, a part mögötti jégmezőkön megbúvó rettentő szörnyekről. E messzi északon lankadatlan harc folyik a kegyetlen természet erőivel, az inuitokkal, hataloméhes, gátlástalan földbirtokosokkal, miközben az egyház is felveszi kilátástalan küzdelmét a pogányság terjedése ellen. A körülmények összjátéka végletes jellemeket formál: vak kapzsiságot, önzést, bátorságot és önfeláldozást.
INSERT INTO "books" VALUES('',0,'','',112,0,0,0,0,16,'',0,'',10,40,'',250,NULL,NULL,1000,1000,5,NULL,5,11,2009,219,'Pásztor Péter','Kóca és az ismeretlen','978-963-9934-44-3',2,'','2','120x200 mm',100,'0',1490,2,'Judák Tamás LEZÁRVA ->§438','Pasztor-Peter','','http://bookline.hu/product/home!execute.action?id=84671&type=22&_v=Pasztor_Peter_Koca_es_az_ismeretlen','','http://www.fo.hu/hu/konyv/szepirodalom/ifjusagi_irodalom/regenyek/koca_es_az_ismeretlen','','','','',5,3,0,7,4,5,3,'2009-9-28','2009-11-5','Judák Tamás, 2347 Bugyi, Alsóvány-puszta 47., T.: 70/568-6796','bobitaskoca@gmail.com','','Négy fiatal manó, kik egy fában élnek, kíváncsiságuk miatt mind távolságban, mind saját múltjukban olyan messzire keverednek, mit maguk sem sejtettek. Kócát szárnyai alá veszi a vén könyvtáros, Fátyolka ajándékba kap egy szivárványpillangót, találkoznak a vízisárkányok népével, és mindeközben egy különös idegen után kezdenek kutatni, akitől azt remélik, hogy választ ad megannyi kérdésükre...','2009.ZKI:478+1=479
INSERT INTO "books" VALUES('',0,'','Agnes_B_Iron--Nehez_eset--FD.jpg','','',1,1,0,12,'',0,1574,10,'','','',NULL,NULL,'','',0,NULL,20,11,2009,220,'Agnes B. Iron','Nehéz eset','978-963-9934-46-7',2,'','2','A5',258,'0',2500,5,'Csukáné Berdó Ágnes','Agnes-Iron','http://www.konyvesbolt.online/spd/978-963-9934-46-7/Agnes-B--Iron-Nehez-eset-Ad-Librum','','','','','','','',3,3,0,7,4,5,5,'Array-0-0','2009-11-20','Csukáné Berdó Ágnes 30/227-8336','melody.m@citromail.hu','','Túl keveset tudok rólad. Oly kevéssé ismerlek. De amit megismertem, az jó és nemes. Szeretném ismerni az érzéseid, a gondolataid, a titkaid. Mire vágysz, mi az, mi lázba hoz, s felizgat? Látni a lelked, a szíved, s tudni, képes vagy-e sírni azért, kit igazán szeretsz? Álmodom rólad, s közben elkerüllek, mert ha látlak, belefájdul a szívem, görcsbe rándul a gyomrom. Ha a hangod hallom, beleborzongok, ha a szemedbe nézek, elveszek benne, mint a sötét éjszakában. Minden nap rád gondolok. Egy ábránd vagy csupán, egy szép álom, melyet nem akarok feledni soha. Te vagy minden, ami szép és jó, te vagy minden, ami lehet, vagy lehetne, te vagy minden a szívemben. Szeretlek!','2009.ZKI:18+1=19
