INSERT INTO "books" VALUES('',0,'','Jepont--Utcakonyv--FD.jpg','',0,1,0,0,4,'',1,'',40,70,'','',NULL,NULL,'',100,0,NULL,20,11,2009,236,'Váczy Jépont Tamás','Egy idegenvezető magánélete (Utcakönyv)','978-963-9934-57-3',2,'','2','A5',128,'0',1990,1,'#LA4 Szabóné Váczi Borbála','Jepont','http://www.konyvesbolt.online/spd/978-963-9934-57-3/Vaczy-Jepont-Tamas-Egy-idegenvezeto-maganelete-Utc','http://bookline.hu/product/home!execute.action?id=85373&type=22&_v=Vaczy_Jepont_Tamas_Egy_idegenvezeto_maganelete','','http://www.fo.hu/hu/konyv/szepirodalom/memoar_eletrajz_interju/egy_idegenvezeto_maganelete_utcakonyv','http://www.konyvesbolt.online/spd/978-963-9934-57-3/Vaczy-Jepont-Tamas-Egy-idegenvezeto-maganelete-Utc','','','',3,3,0,9,4,5,1,'Array-0-0','2009-11-20','Borka','boribakter@gmail.com','Váczy Jépont Tamás, az ismert grafikusművész-író – középső nevét Latinovitstól és Nagy Lászlótól kapta – első posztumusz, teljes kiadású könyve.','„Alig kell nagyobb felület, mint egy gyufásdoboz és rajzolhatunk. Egy levesestányér aljára festett cérnametélt, ha pontos, hosszú ideig kapirgálható.
INSERT INTO "books" VALUES('',0,'','Simon_Weber--Ezustnyilak--FD.jpg',223,'',1,0,0,31,'',1,'',40,60,'','',NULL,NULL,'',1000,0,NULL,23,8,2012,237,'Simon Weber','Ezüstnyilak - Mercedes-Benz Motorsport','978-615-5110-52-8',2,'','5','A5',180,'0',3790,1,'#LB2,LGII,LGVI#   B5 Szerző: Gugó Csaba 12 ff és 8 színes képoldal T&B:V','','http://www.konyvesbolt.online/spd/978-615-5110-52-8/Simon-Weber-Ezustnyilak---Mercedes-Benz-Motorsport','','','','','','','',3,3,4,7,4,5,3,'2012-5-16','2012-8-23','9400 Sopron, Malomházi u. 28. 30/258-7799','csgugo@gmail.com','','Egy autógyártó sem büszkélkedhet olyan eredményekkel az autósportban, mint a Mercedes-Benz. A világ első autóversenyét 1894-ben Daimler által készített motorral nyerték meg, a második világháború előtti Grand Prix-viadalokon pedig a Mercedes-Benz szinte verhetetlen volt. A márka a világégés után is földbe döngölte a konkurenciát, és két év alatt két Formula–1-es világbajnokságot nyert a legendás Juan-Manuel Fangio révén. A cirkuszban a McLaren és a Brawn autóit is Mercedes motor röpítette a bajnoki cím felé, de más versenyágakban is ragyogó győzelmeket szerzett a Mercedes. A stuttgarti márka sikeres volt a sportkocsik között, a ralipályákon; az Indy 500, valamint számtalan prototípus és DTM-győzelem is a cég autósport melletti elkötelezettségét bizonyítja.
INSERT INTO "books" VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,10,'',0,'',5,20,'',75,NULL,NULL,300,300,5,NULL,8,2,2010,238,'Stephanie Ford','Véres lábnyomok a levegőben','978-963-9934-58-0',2,'','3','148x210 mm',400,'0',2990,2,'#D T:G B:B Guth István Károlyné (Lovasi Tünde)','Stephanie-Ford','','','','','','','','',5,3,0,7,4,5,5,'2009-11-0','2010-2-8','Guth István Károlyné (Lovasi Tünde) T.: 29/350-033 C.: 2220 Vecsés, Major u. 7/a.','lovasitunde@gmail.com','','Jackie Simonnal madarat lehetne fogatni, mikor megtudja, hogy egy rendőrcsere-program keretén belül elutazhat Rockswoodba nyomozói tapasztalatot szerezni. Kicsit csodálkozik ugyan, minthogy ő nem nyomozó, ám a lehetőségnek azért örül. Fogalma sincs, hogy úti céljának legfőbb nevezetessége – ha van ilyen egyáltalán –, hogy szinte egyáltalán nem történnek bűnügyek, mint ahogyan arról sem, hogy leendő főnöke rendőr ugyan, ám jelenlegi pozícióját egyféle felfelé buktatásnak köszönheti. Mindössze egyetlen közös vonásuk van: a tapasztalat hiánya. Épp ezért éri sokként a friss társakat, hogy nem sokkal Jackie megérkezése után furcsa gyilkosság történik: egy helybéli, gazdag család villájában rábukkannak a látogatóba érkező rokon kamaszlány holttestére, amely körül szemmel láthatóan nincs minden rendben… És ezzel elindul a lavina: több haláleset követi egymást, amelyeknek van egy igen különös közös mozzanata. Ráadásul az álmos vidéki városban felbukkanó fi lmes stábnak köszönhetően hirtelen igencsak felpezsdül az élet – alaposan megnehezítve botcsinálta nyomozópárosunk dolgát. Vajon sikerül-e felgöngyölíteni a levegőben lebegő véres lábnyomok és a gyilkosságok rejtélyét főhőseinknek, vagy Rockswood immár az örökre megoldatlan, misztikus halálesetekről lesz híres-hírhedt?','A plusz 10 példány maradt saját haszonra.
INSERT INTO "books" VALUES('',0,'','Leon_Maxwell_Fate--Aki_eletben_marad--FD.jpg','','',1,1,0,11,'',1,2300,10,'','','',NULL,NULL,'',30,0,NULL,14,1,2010,239,'Leon Maxwell Fate','Aki életben marad','978-963-9934-61-0',2,'','2','A5',500,'0',2990,5,'#LA6 Bakos Levente','Leon','http://www.konyvesbolt.online/spd/978-963-9934-61-0/Leon-Maxwell-Fate-Aki-eletben-marad-Ad-Librum-2010','','','','','','','',3,3,0,7,0,0,4,'Array-0-0','2010-1-14','Bakos Levente T.: 70/226-5053','bakos666@vipmail.hu','','2008 október 09. csütörtök
INSERT INTO "books" VALUES('',0,'','Ozory_Zorka--Sorsmetszetek--FD.jpg',194,'',1,0,0,12,'',1,'',40,70,'','',NULL,NULL,'',500,0,NULL,10,12,2009,240,'Ozory Zorka','Sorsmetszetek','978-963-06-8459-0',1,'','2','125x200 mm',80,'0',1990,1,'#LD,LGV#   T:G B:B','Ozory-Zorka','http://www.konyvesbolt.online/spd/978-963-06-8459-0/Ozory-Zorka-Sorsmetszetek-2009','http://bookline.hu/product/home!execute.action?id=85510&type=22&_v=Ozory_Zorka_Sorsmetszetek','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/sorsmetszetek','','','','',3,3,2,7,4,5,5,'2009-11-11','2009-12-10','30/748-39-34, Kómár Anett Adrienn, 1085 Budapest, Üllői út 20.','komar.anett@freemail.hu','Szókimondó könyv a szerelemről.','„Azt kértem tőle, mondja meg, mi a szeretet. Egy percet sem gondolkodott a válaszon, és kinyilatkoztatása mintha őt magát is meglepte volna. A dolgok önmagáért létező lényege – felelte. Pár perc csend után újra megszólalt: – Most már értem. Ezért vagyunk képesek bármit szeretetté változtatni. Ha teljes figyelemmel szemléljük és alakítjuk azt, ami fontos nekünk, a lényeg felszínre tör, pusztán a megfigyelés által. Így lehetséges tökéleteset alkotni. Most menj haza, gondolkodj el ezen, gyere vissza egy hét múlva. Szeretkezni fogunk, de nem úgy, mint eddig. Ha megértetted a mondanivalómat, tudni fogod, mire gondolok.”
INSERT INTO "books" VALUES('',0,'','','','',1,2,0,12,'',0,'','','','','',NULL,NULL,'',49,0,NULL,18,12,2009,241,'Anita Gayn','Senkinek sem kellesz!','978-963-06-8585-6',1,'','3','A5',505,'0','',1,'#LB6','Anita-Gayn','','','','','','','','',3,3,1,7,4,5,3,'2009-11-13','2009-12-18','Nagy Anita, 7666 Pogány, Móricz Zsigmond utca 8.','lanaswan@freemail.hu','','','Bemutatópl.:1 db
INSERT INTO "books" VALUES('',0,'','Kovacs_Laszlo--Kartyasok_a_tuzhanyon--FD.jpg','',0,1,0,0,3,'',1,'',40,65,'','',NULL,NULL,'',49,0,NULL,7,12,2009,242,'Kovács László','Kártyások a tűzhányón','978-963-9934-59-7',2,'','3','A5',86,'0',2100,1,'','Kovacs-Laszlo','','','','','','','','',3,2,1,7,4,5,3,'2009-11-16','2009-12-7','1144 Budapest, Tihany út 42-44. fsz. 12., 220-1413','laszlone.kovacs@chello.hu','','Kovács László Sárváron született 1944-ben. A Tinódi Sebestyén Gimnáziumban tett érettségije után az ELTE bölcsészettudományi karán és a Szombathelyi Tanárképző Főiskolán tanult. Évtizedekig állt a katedrán, pályafutása a budapesti Hajnik Károly Közgazdasági Szakközépiskolában töltött tizenöt év német nyelvtanári és könyvtárosi működéssel zárult. Első elbeszélését a regenytar.hu 2005. évi Novellapályázat rovata közölte. Kisesszéi, novellái jelentek meg a Kláris irodalmi-kulturális folyóiratban, karcolatai a Magyar Fórumban, valamint novellái az Ausztria nekünk című antológiában (Vitis Aureus, 2009). Első önálló, kisprózai írásokat tartalmazó kötete (Az éhes őrnagy) az Ad Librum kiadásában látott napvilágot 2009-ben. Most második önálló kötetével jelentkezik. A címadó szatírikus írást elsőként a Mentrópia (www.mentropia.hu) tette közzé 2009-ben.
