INSERT INTO "books" VALUES('',0,'','Locskai_Denes--Kisertetkastely--FD.jpg','','',1,1,11,14,'',1,1340,10,'','','',NULL,NULL,'',30,0,NULL,2,2,2010,265,'Locskai Dénes','Kísértetkastély – A Kezdet','978-963-06-8682-2',1,'','3','130x200 mm',180,'0',1690,5,'#LA6 T:G,B:V','Locskai-Denes','http://www.konyvesbolt.online/spd/978-963-06-8682-2/Locskai-Denes-Kisertetkastely-A-Kezdet-2010','','','','','','','',3,3,1,7,3,5,4,'2009-12-0','2010-2-2','Locskai Dénes, 06-30-6770940, 6500 Baja, Bara utca 4/C 2e. 9a.','locskai.denes@gmail.com','','Egy esős nyári délutánon a Franklin család vakációra indul. Az utazás azonban nem indul szerencsésen. Véletlen események folytán egy elhagyatottnak látszó kastélyban találják magukat. Hamar rájönnek, hogy nincsenek egyedül, de menekülni már túl késő. Az ekkor még csak 12 éves Jennifer ugyan túléli a borzalmakat, de elveszti az emlékezetét. Egy kedves család fogadja örökbe, akik saját gyermekükként nevelik fel. Azonban a múlt árnyai nem hagynak békét a lánynak. 10 évvel később rémálmok kezdik gyötörni, melyekben egy kastélyról, egy családról és egy tőle segítséget kérő kisfiúról álmodik. Nem hagyják nyugodni a történtek, ezért nyomozni kezd, s kideríti, hogy a kisfiú valójában az ő testvére, de már évekkel ezelőtt meghalt; a család pedig az ő családja volt, de emlékei még ennek ellenére sem tértek vissza. Úgy dönt, felkeresi a kastélyt, hogy kideríthesse mi is történt valójában, de egyedül nem mer odamerészkedni, ezért csellel magával viszi néhány barátját.
INSERT INTO "books" VALUES('',0,'','Palmer,_Tom_G--Erkolcsos_kapitalizmus--FD.jpg',222,'',1,0,43,27,'',0,'',40,60,'','',NULL,NULL,'',500,0,NULL,20,12,2012,266,'Tom G. Palmer (szerk.)','Az erkölcsös kapitalizmus','978-615-5014-67-3',2,'','5','130x200 mm',192,'0',2290,1,'#LD#  K:K B:B T:G','','http://www.konyvesbolt.online/spd/978-615-5014-67-3/Tom-G--Palmer-szerk--Az-erkolcsos-kapitalizmus-Ad-','','','','','','','',3,3,3,7,4,5,3,'2012-11-2','2012-12-20','Global Education Kft. (képviseli:  Kész Zoltán), Telefon: 30/9523-697, 8200 Veszprém, Kinizsi u. 7.','kesz.zoltan@gmail.com','A szabadpiaci kapitalizmus védelmében.','A kapitalizmus nem csak arról szól, hogy emberek helyi piacokon vajat cserélnek tojásra, mint ahogy az évezredeken keresztül történt. A kapitalizmus lényege az értékteremtés, az emberi energia és találékonyság az emberiség történelme során eddig soha nem látott mértékű mozgósításán keresztül annak érdekében, hogy az átlagemberek számára olyan jólétet teremtsenek, ami a múlt leggazdagabb és leghatalmasabb királyait, szultánjait és császárait is elkápráztatta és megdöbbentette volna. A kapitalizmus a régóta körülbástyázott, kiváltságokon alapuló hatalmi-uralmi rendszerek lebontásáról és a karrier lehetőségének a tehetségek számára történő megnyitásáról szól. A kapitalizmus az erőszak meggyőzés általi és az irigység beteljesülés általi felváltásáról szól. A kapitalizmus lényege mindaz, ami lehetővé tette az életet, így a Te életedet is. (Tom G. Palmer)
INSERT INTO "books" VALUES('',0,'','Simian--Lokottek_kozott--FD.jpg',227,0,1,0,0,18,'',0,'',0,0,'','',NULL,NULL,'',100,0,NULL,19,4,2010,267,'C. Simian','Lököttek között','978-963-06-8705-8',1,'','3','140x200 mm',180,'0',1490,1,'#RA1 Kiss Elemér T:G B:V','C-Simian','http://www.konyvesbolt.online/spd/978-963-06-8705-8/C--Simian-Lokottek-kozott-2010','','','','http://www.konyvesbolt.online/spd/978-963-06-8705-8/C--Simian-Lokottek-kozott-2010','','','',3,3,0,7,4,5,3,'Array-0-0','2010-4-19','Kiss Elemér 20/801-8818 - 2645 Nagyoroszi, Bajcsy u. 55.','','Történetek a folyami hajósok elmúlt életéből.','A szellem a tengerparton sétált. Nem volt se szomorú, se vidám. Csodálkozva nézte a kétlábú húslényeket, akikkel találkozott. Beleszülettek a jellegtelenségbe, és belehalnak a jellegtelenségbe. Gravitációs katasztrófát szenvedtek, mint a fekete lyukak. Napról napra aggódva múlatják az időt. Bár lehet, hogy az idő nincs is, csak ők találták ki. Ha lenne, a kutya is megünnepelné az új esztendőt. Mindezek ellenére önmaga apróka szikráját vélte felfedezni bennük. Mindent összevetve nagyon szerencsétlennek találta őket, sőt nevetségesnek. Nevetett is volna, ha sok-sok évvel ezelőtt el nem jut a bölcsesség azon fokára, ahonnan már nem nevetünk ki senkit...','11-08-07: #RAa1a 20 pld. (stimmel)
