INSERT INTO "books" VALUES('',0,'','Kopor_Tihamer--Folyondar--FD.jpg',240,0,1,0,0,4,'',1,'',5,20,'',75,NULL,NULL,300,300,5,NULL,10,5,2010,279,'Kopor Tihamér','A Folyondár','978-963-9934-73-3',2,'','3','A5',180,'0',2290,2,'#LGI,LB3# T:G B:B','Kopor-Tihamer','http://www.konyvesbolt.online/spd/978-963-9934-73-3/Kopor-Tihamer-A-Folyondar-Ad-Librum-2010','','','','http://www.konyvesbolt.online/spd/978-963-9934-73-3/Kopor-Tihamer-A-Folyondar-Ad-Librum-2010','','','',3,3,0,7,4,5,5,'Array-0-0','2010-5-10','30/211-1963  2030 Érd, Talabor u. 42.','kate.kopor.tihu@gmail.com','Négy ember karmikusan meghatározott egymáshoz tartozása.','„Mindenkinek csak ajánlani tudom… Nagyon belterjes ez a történet. Mint egy görög dráma, amelynek hősei egy városban élnek generációk óta, sorsuk számtalan alkalommal összefonódott… A múltnak súlya van ebben a könyvben.”
INSERT INTO "books" VALUES('',3,'','Yasmin_Hondar_Gomez--Compartiendo--FD.jpg',159,0,1,2,0,31,'',0,'','','','','',NULL,NULL,'',100,0,NULL,15,8,2014,280,'Yasmín Hondar Gómez','Compartiendo sueños con mis amigos de Vento','978-615-5110-65-8',2,'','7','140x200 mm',120,'0',2978,1,'#LB5,LG8# spanyol nyelvű','','http://www.konyvesbolt.online/spd/978-615-5110-65-8/Yasmin-Hondar-Gomez-Compartiendo-suenos-con-mis-am','','','','http://www.konyvesbolt.online/spd/978-615-5110-65-8/Yasmin-Hondar-Gomez-Compartiendo-suenos-con-mis-am','','','',3,3,1,9,4,5,5,'2014-1-0','2014-8-15','','','','Esta sencilla novela describe la vida de los alumnos de la Escuela Vocacional de Vento en los años del 68 al 71 del siglo pasado. Este texto no solo es mío; es de todos aquellos que me ayudaron a reconstruir pedazos de nuestra juventud.
INSERT INTO "books" VALUES('',0,'','Janurik_Tamas--A_romani_nyelv_alapjai--FD.jpg',170,'',1,1,0,35,'',1,1208,10,'','','',NULL,NULL,'',50,0,NULL,24,2,2010,281,'Janurik Tamás','A romani nyelv alapjai','978-963-9934-75-7',2,'','3','200x140mm',136,'0',1990,5,'#LA5','Romani','http://www.konyvesbolt.online/spd/978-963-9934-75-7/Janurik-Tamas-A-romani-nyelv-alapjai-Ad-Librum-201','','','','','','','',3,3,1,9,4,5,5,'2010-2-0','2010-2-24','Dr. Janurik Tamás 20/316-1400  8000 Székesfehérvár, Ady Endre u. 22.','janurik.tamas@freemail.hu','','Dr. Janurik Tamás magyar és összehasonlító nyelvész, a Kecskeméti Főiskola professor emeritusa, a nyelvtudományok kandidátusa, különböző európai nyelvek kutatója. A romani nyelvet (illetve annak standardizált nyelvi változatát, a lovárit) évek óta tanítja a főiskolán.
