INSERT INTO "books" VALUES('',0,'','Magyar_B_Attila--Viragszerda--FD.jpg','',0,1,1,0,4,'',1,1460,10,'','','',NULL,NULL,'',20,0,NULL,1,4,2010,301,'Magyar B. Attila','Virágszerda','978-963-9934-85-6',2,'','3','A5',220,'0',1650,5,'#LB4,LG7#   Balog Sándor','Magyar-B-Attila','http://www.konyvesbolt.online/spd/978-963-9934-85-6/Magyar-B--Attila-Viragszerda-Ad-Librum-2010','','','','http://www.konyvesbolt.online/spd/978-963-9934-85-6/Magyar-B--Attila-Viragszerda-Ad-Librum-2010','','','',3,3,0,9,4,5,5,'2010-3-17','2010-4-1','Balog Sándor T.: 20/423-68-23 Cím: 1155 Bp., Mézeskalács tér 15. II/2.','balogford2@mail.datanet.hu','Vidám hangvételű, kizárólag párbeszédeket tartalmazó kisregény.','A vidám hangvételű, kizárólag párbeszédeket tartalmazó kisregény cselekménye 2005 tavaszán játszódik. Szereplői nagy összegű fogadás kapcsán keresik a feleletet a csaknem kétezer éve megválaszolatlan kérdésre: Valóban három nappalt és három éjszakát volt a sírban Jézus, ahogy megjövendölte, vagy péntek délutántól vasárnap hajnalig? Miért, talán nem mindegy? – kérdezhetné bárki. A történetből kiderül, hogy egyáltalán nem az!','Változik a telefonszáma, most éppen: 30-9918-049. De a végleges: 20-423-68-23.',NULL,1451300122,0);
INSERT INTO "books" VALUES('',1,'','Attila_B_Magyar--Palm_Wednesday--FD.jpg','','',1,1,0,4,'',1,1364,10,'','','',NULL,NULL,'',20,0,NULL,1,4,2010,302,'Attila B. Magyar','Palm Wednesday','978-963-9934-84-9',2,'','3','A5',188,'0',1650,5,'','Magyar-B-Attila','http://www.konyvesbolt.online/spd/978-963-9934-84-9/Attila-B--Magyar-Palm-Wednesday-Ad-Librum','','','','','','','',3,3,1,9,4,5,5,'2010-3-17','2010-4-1','Balog Sándor T.: 20-423-68-23 Cím: 1155 Bp., Mézeskalács tér 15. II/2.','balogford2@mail.datanet.hu','An entertaining, short novel, consisting entirely of dialogues.','This entertaining, short novel, consisting entirely of dialogues, takes us back to the spring of 2005. The novel’s main protagonists, in order to win a large sum of money that has been wagered, try to find the answer to a question that has remained unanswered for almost 2,000 years: Did Jesus spend three days and three nights in the tomb, as he had foretold, or was he really only there from Friday afternoon until the early hours of Sunday morning? Some might think the question pointless and in their turn ask the question: Does it matter? After reading the story it will become clear to the reader that, yes, it really does matter!','Változik a telefonszáma, most éppen: 30-9918-049. De a végleges: 20-423-68-23.',NULL,1460370308,0);
INSERT INTO "books" VALUES('',0,'','Mickey_Miller--Kairoi_gyilkossagok--FD.jpg','',0,1,1,0,11,'',1,1380,10,'','','',NULL,NULL,'',60,0,NULL,10,5,2010,303,'Mickey Miller','Kairói gyilkosságok','978-963-9934-91-7',2,'','3','A5',195,'0',1800,5,'#LB6 T:G B:Szerző Molnár Miklós','Mickey-Miller','http://www.konyvesbolt.online/spd/978-963-9934-91-7/Mickey-Miller-Kairoi-gyilkossagok-Ad-Librum-2010','','','','http://www.konyvesbolt.online/spd/978-963-9934-91-7/Mickey-Miller-Kairoi-gyilkossagok-Ad-Librum-2010','','','',3,2,1,7,4,5,3,'2010-3-0','2010-5-10','Molnár Miklós, +36304732856, 1118 Bp., Kelenhegyi út 18., állandó: 9011 Győr, Pengős utca 1.','mmickey84@gmail.com','Klasszikus krimi Egyiptomban.','A történetet egy Egyiptomban töltött, két hetes országos körutazás ihlette. Ezért személyes tapasztalatok és élmények is beépültek a cselekménybe. Annak ellenére, hogy valós szituációk színesítik a művet, mind a történet, mind a helyszínül szolgáló szálloda fiktív, és a szereplők is egytől egyig kitalált alakok. A regény történelmi érdekességekkel, lélektannal és humorral fűszerezett.
INSERT INTO "books" VALUES('',0,'','','','',1,0,30,36,'',0,'',60,60,'','',NULL,NULL,'',120,0,NULL,21,4,2010,304,'Zágon Judit','Álmomban egy farkas… mit jelent? - (270 álom jelentése + álom-szótár)','978-963-9934-92-4',2,'','3','A5',380,'0',2990,1,' #A4 T&B:B Hivatalos lezárásra várva - a szerzőnél a maradék hivatalos példány.','Zagon-Judit','','','','','','','','',3,3,1,7,4,5,3,'2010-3-0','2010-4-21','Zágon Judit, 2013 Pomáz Tavasz utca 3., 06/203970611, 06/26329396','pszichoglass@t-online.hu','','Az álmok a külvilághoz, az életkörülményekhez való alkalmazkodásunkat biztosítják – sokféle módon. Elősegítik a helyes (etikus) és célravezető magatartásformák rögzítését, vagyis megerősítik („memorizálják”) a bevált viselkedés- és gondolatmintáinkat. Helytelen vagy téves stratégiáink megváltoztatására ösztönöznek, provokálják szemléletmódunk megváltoztatását, hogy összhangba kerüljünk a környezetünkkel és önmagunkkal. Hidat képeznek a tudatalattink és a racionális tudatunk között, megpróbálják a kettőt összehangolni. Ezeket a funkciókat az álmok jó esetben a rájuk való emlékezés és megfejtés nélkül is teljesítik. Az álmokra való emlékezés és az álomfejtés tanulható szellemi munka, mely az önismeretet, a tudatos megértést és fejlődést szolgálja.
