INSERT INTO "books" VALUES('',0,'','Dobrossy_Rita--Orokke_fiatalon--FD.jpg','',0,1,0,0,12,'',1,'','','','','',NULL,NULL,'',70,0,NULL,25,7,2013,307,'P. Dobrossy Rita','Örökké fiatalon','978-963-87741-5-6',2,'','6','140x200 mm',120,'0',1990,5,'#LB3','','http://www.konyvesbolt.online/spd/978-963-87741-5-6/P--Dobrossy-Rita-Orokke-fiatalon-Ad-Librum-2013','','','','http://www.konyvesbolt.online/spd/978-963-87741-5-6/P--Dobrossy-Rita-Orokke-fiatalon-Ad-Librum-2013','','','',3,3,4,7,4,5,5,'2013-5-0','2013-7-25','Pásztorné Dobrozsi Rita, 4600 Kisvárda, Rétalja út 1. 45/421-051','dobrozsirita@freemail.hu','','Reggelenként kilovagoltam a házam melletti ösvényen keresztül egy erdei tisztásra, és mindig eszembe jutott, hogy valahol - talán - ott van Ági is, aki annyira örült volna, ha mindezt megérheti.
INSERT INTO "books" VALUES('',0,'','Bratan_Erzsebet--Elni_vagy_olni--FD.jpg','','',1,0,0,4,'',0,1550,8,20,'',30,NULL,NULL,150,150,2,NULL,28,5,2010,308,'Brátán Erzsébet','Élni vagy ölni? Egy vérvonal hattyúdala','978-963-9934-95-5',2,'','3','',250,'0',1990,2,'#LA6# K:D T:G B:V','Bratan-Erzsebet','http://www.konyvesbolt.online/spd/978-963-9934-95-5/Bratan-Erzsebet-Elni-vagy-olni-Egy-vervonal-hattyu','','','','','','','',3,3,2,7,4,5,5,'2010-4-0','2010-5-28','Brátán Erzsébet, 06 20 807 77 26, ideiglenes/postacím: 2091 Etyek, Alsóhegy u. 38., állandó: 2051 Biatorbágy, Biai G. u. 43.','bratanerzsi@gmail.com','','"Az ezoterikus és alternatív gyógyászati írásokat jegyző szerzőt egy vidéki kastélymúzeumban tett látogatás inspirálta e regény megírására. Brátán Erzsébet ezért könyve elején egy kis történelemleckét tart tankönyvi idézettel, hogy behatárolja történetének időhatárait. A néhány oldalas idézetből megtudjuk: az 1848-as szabadságharc leverésétől az 1956-os forradalom leveréséig ágyazódik a történelem szövetébe a keresztnevükön szerepeltetett nagybirtokos báró család tagjainak sorsa. A fő szál József úrfi és a szolgálólány, Mária szerelme, ehhez kapcsolódnak a fantázia szülte, de valóságosnak ható szereplők. "Milyen volt az élet ezekben az időkben a fővárostól távol? A távoli uradalmakban, kisfalvakban és a tanyákon, a vérkeringéstől eldugott területeken?" - írja a szerzőnő elöljáróban."','Korr. ápr. 25-re.
