INSERT INTO "books" VALUES('',0,'','Mrazik_Julianna--A_tanarok_hangja--FD.jpg',295,'',1,1,0,43,'',1,1514,10,'','','',NULL,NULL,'',50,0,NULL,29,7,2010,326,'Mrázik Julianna','A tanárok hangja – Hogyan vélekednek hivatásukról a pedagógusok?','978-615-5014-07-9',2,'','3','',238,'0',1990,5,'#LA2 T&B:V','Mrazik-Julianna','http://www.konyvesbolt.online/spd/978-615-5014-07-9/Mrazik-Julianna-A-tanarok-hangja-Hogyan-velekednek','','','','','','','',3,3,1,7,4,5,5,'2010-6-0','2010-7-29','Mrázik Julianna, 70/206-2407, 7629 Pécs, Feketegyémánt tér 21.','julimrazik@gmail.com','','A szerző valódi probléma vizsgálatára vállalkozott: kutatásának célja az volt, hogy feltárja az ezredforduló utáni valós, hazai pedagógusproblémákat, és azt, hogy ezek a problémák milyen súlyúak, s milyen mértékben befolyásolják a változó pedagógusszerep-megformálást. Megragadott számos, a vizsgált pedagógusok szempontjából lényeges problémát, ezeket elhelyezte egy elméleti, szakmai keretbe és felvillantotta az eredmények alkalmazhatóságának lehetőségeit kutatásmódszertani, tanárképzési és tanár-továbbképzési aspektusból.
