INSERT INTO "books" VALUES('',0,'','','',0,0,0,0,8,'',1,'',20,20,'','','','','','',0,'',15,11,2010,402,'Füst Antal','Koronás hegyek – A Zagyva-völgyi várak regénye','978-615-5014-79-6',2,'','3','','','0',990,6,'#L K:K,B:V,T:G §362','Fust-Antal','','','','','','','','',3,3,3,7,4,5,5,'2010-9-10','2010-11-15','Dr. Füst Antal, 30/353-2766, 1142 Budapest, Nezsider park 2.','antalfust@gmail.com','Történelmi rege a török idők várairól.','A Zagyva-völgyi várak megmaradt kövei, ma is valami különleges erőt sugároznak. Ostromágyúk által szaggatott falaikkal, felhőkbe törő csonka lakótornyaikkal a magyarság nagy próbatételeit idézik, példát mutatnak az utókornak, vitézségből és helytállásból. A késői utódok borzongva mesélik a védők hőstetteit, menekülő alagutakról, nagy szerelmekről és még nagyobb tragédiákról suttognak. A kövek pedig továbbra is féltékenyen őrzik a titkokat.
INSERT INTO "books" VALUES('',0,'','Toldi_Nagy_Miklos--Humor_a_petrencen--FD.jpg',206,0,1,0,0,20,'',1,'',40,60,'','',5,250,'',310,0,'',10,7,2009,403,'Toldi Nagy Miklós','Humor a petrencén','978-963-9888-32-6',2,'','2','A5',144,'0',2290,1,'#LD1,LG20# BIZOMÁNYOSI §172 duplikálása','Toldi-Nagy-Miklos','http://www.konyvesbolt.online/spd/978-963-9888-32-6/Toldi-Nagy-Miklos-Humor-a-petrencen-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=82026&type=22&_v=Toldi_Nagy_Miklos_Humor_a_petrencen','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/egyeb_felnottirodalom/humor_a_petrencen','http://www.konyvesbolt.online/spd/978-963-9888-32-6/Toldi-Nagy-Miklos-Humor-a-petrencen-Ad-Librum-2009','','','',3,3,1,7,4,1,5,'2009-6-0','2009-7-10','Toldi Miklós; 2100 Gödöllő, Szarvas u. 10.; (30)972-3017','toldi.miklos@invitel.hu','A Rádiókabaré szerzőjének szó- és egyéb viccei.','1951-ben születtem Budapesten.  A Színművészeti Főiskola zenés színész szakának elvégzése után két évet prózai színészként is dolgoztam. Ezután különböző zenés színházaknál operát énekeltem 24 éven át. A Népszínháztól mentem nyugdíjba. Írással 12 éve foglalkozom. A Rádiókabaré is többször leadott az anyagomból. Könnyen írok, mert nagy nyugalomban és gondtalanul élek. Ha megkérdezik tőlem, hogy vagyok, a válasz: Ember jobban nem lehet! Egy napi problémákkal küszködő ember agyában ennyi marhaság nem születik meg. Nagy kertem van, ahol szőlészkedem is.  Azt tartom, hogy a kert szüli, a bor hizlalja a gondolatot. Hitvallásom: Ha sokáig akarsz élni, ne tartózkodj siránkozó emberek társaságában.
INSERT INTO "books" VALUES('',0,'','','','',0,0,0,16,'',1,'',20,20,'','','','','','',0,'',15,11,2010,404,'Enrico Angelotti','Évszaktündérek','978-615-5014-19-2',2,'','3','','','0',990,6,'Sörös László T:G B:B','Angelotti','','','','','','','','',3,3,1,7,4,5,5,'2010-4-0','2010-11-15','Sörös László, 8109 Tés, Felszabadulás u. 65., 20/349-0965','laszlo.soros@freemail.hu','Sikerül-e a vándordiáknak kiszabadítani Arabella hercegkisasszonyt, aki az Ezerarcú Szellem fogságában raboskodik? Évszakmesék.','Tavasz után nyár, nyár után az ősz, majd a tél. Így változnak az évszakok örökös körforgásban, mióta világ a világ. Falevelek hullnak, hópelyhek szállingóznak, tavaszi virágok nyílnak, sárgán izzik a nyári nap. Minden évszaknak megvannak a maga sajátosságai, s a maga sajátos történetei.
INSERT INTO "books" VALUES('',0,'','','','',0,0,0,3,'',1,'',20,20,'','','','','','',0,'',15,11,2010,405,'Mester Györgyi','Tisztítótűz','978-615-5014-08-6',2,'','3','','','0',790,6,'','Mester-Gyorgyi','','http://bookline.hu/product/home!execute.action?id=81301&type=22&_v=Mester_Gyorgyi_Tisztitotuz_Valogatott_novellak','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/tisztitotuz_valogatott_novellak','','','Mester_Gyorgyi_3-Tisztitotuz-','',3,3,0,7,4,0,0,'2009-4-27','2010-11-15','','mestergyorgyi@freemail.hu','Az Egyesült Hínár Szakszervezettől a szivárványos tafotán át az EU saját halottjáig: a Legjavából, a Fehéren-feketén és a Haláli (jó) történetek szerzőjének legújabb történetei.','„Kellően felpaprikázott hangulatban lépett be az irodába, majd táskáját az asztalra csapva,  nekiállt, hogy levetkőzzön. Kabátját a fogasra akasztva, gyors pillantást vetett a tükörbe, és akkor látta meg, hogy a haja ott hátul, égnek áll. És ő így jött végig az utcán! Az ágaskodó tincset lesimította, sötét szemüvegét pedig kicsit feljebb tolta az orrán. Nem volt rá igazán szüksége, csupán kis dioptria volt az egyik lencsén, de úgy gondolta, a negyvenes évei elején  érdekesebbé, modernebbé, talán fiatalosabbá is teszi, a sötétített foncsorozású, divatos szemüveg. Ez tette-e, vagy csak a sors játszott vele aznap reggel, de minden balul ütött ki. A szemüvegtől függetlenül, sötéten látta az egész világot, és benne önmagát. 
INSERT INTO "books" VALUES('',0,'','','','',0,0,0,11,'',1,'',20,20,'','','','','','',0,'',16,11,2010,406,'Mickey Miller','Kairói gyilkosságok','978-615-5014-88-8',2,'','3','',195,'0',990,6,'T:G B:Szerző Molnár Miklós','Mickey-Miller','','','','','','','','',3,2,1,7,4,5,5,'2010-3-0','2010-11-16','Molnár Miklós, +36304732856, 1118 Bp., Kelenhegyi út 18., állandó: 9011 Győr, Pengős utca 1.','mmickey84@gmail.com','','A történetet egy Egyiptomban töltött, két hetes országos körutazás ihlette. Ezért személyes tapasztalatok és élmények is beépültek a cselekménybe. Annak ellenére, hogy valós szituációk színesítik a művet, mind a történet, mind a helyszínül szolgáló szálloda fiktív, és a szereplők is egytől egyig kitalált alakok. A regény történelmi érdekességekkel, lélektannal és humorral fűszerezett.
INSERT INTO "books" VALUES('',0,'','','','',0,0,0,11,'',1,'',20,20,'','','','','','',0,'',20,11,2010,407,'Stephanie Ford','Támadás','',2,'','3','','','0',990,6,'Lovasi Tünde','Stephanie-Ford','','','','','','','','',4,3,1,0,1,1,5,'2010-11-0','2010-11-20','Lovasi Tünde, 2220 Vecsés, Major u. 7/a., 29/350-033','lovasitunde@gmail.com','','``Nikola a piros, kényelmesnek látszó fotelt vette észre először, melynek magas támlája a fejet is megtámasztotta. A mögötte lévő ugyanolyan volt, és a mögött lévő is. Messzebb pillantott, és egyszer csak ott ült a halott nő. Az első percben teljesen természetesnek tűnt, hogy ott van. Egyetlen dolog zavarta meg az összhatást, a beszáradt barna folt a ruháján. És amikor még távolabb tekintett, a túlsó három széken is kiterjedt barna foltokat látott. 
INSERT INTO "books" VALUES('',0,'','','',0,0,0,0,10,'',1,'',20,20,'','','','','','',0,'',15,11,2010,408,'Stephanie Ford','Véres lábnyomok a levegőben','978-615-5014-86-4',2,'','3','','','0',1490,6,'T:G B:B Guth István Károlyné (Lovasi Tünde)','Stephanie-Ford','','','','','','','','',4,3,0,7,4,5,5,'2009-11-0','2010-11-15','Guth István Károlyné (Lovasi Tünde) T.: 29/350-033 C.: 2220 Vecsés, Major u. 7/a.','lovasitunde@gmail.com','','Jackie Simonnal madarat lehetne fogatni, mikor megtudja, hogy egy rendőrcsere-program keretén belül elutazhat Rockswoodba nyomozói tapasztalatot szerezni. Kicsit csodálkozik ugyan, minthogy ő nem nyomozó, ám a lehetőségnek azért örül. Fogalma sincs, hogy úti céljának legfőbb nevezetessége – ha van ilyen egyáltalán –, hogy szinte egyáltalán nem történnek bűnügyek, mint ahogyan arról sem, hogy leendő főnöke rendőr ugyan, ám jelenlegi pozícióját egyféle felfelé buktatásnak köszönheti. Mindössze egyetlen közös vonásuk van: a tapasztalat hiánya. Épp ezért éri sokként a friss társakat, hogy nem sokkal Jackie megérkezése után furcsa gyilkosság történik: egy helybéli, gazdag család villájában rábukkannak a látogatóba érkező rokon kamaszlány holttestére, amely körül szemmel láthatóan nincs minden rendben… És ezzel elindul a lavina: több haláleset követi egymást, amelyeknek van egy igen különös közös mozzanata. Ráadásul az álmos vidéki városban felbukkanó fi lmes stábnak köszönhetően hirtelen igencsak felpezsdül az élet – alaposan megnehezítve botcsinálta nyomozópárosunk dolgát. Vajon sikerül-e felgöngyölíteni a levegőben lebegő véres lábnyomok és a gyilkosságok rejtélyét főhőseinknek, vagy Rockswood immár az örökre megoldatlan, misztikus halálesetekről lesz híres-hírhedt?','','',1378144516,0);
INSERT INTO "books" VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,3,'',1,'',15,15,'','','','','','',0,'',15,11,2010,409,'Mester Györgyi','Haláli (jó) történetek','978-615-5014-11-6',2,'','3','','','0',990,6,'','Mester-Gyorgyi','','','','','','','','Ad_Librum--Mester_Gyorgyi--Halali_jo_tortenetek--Kulonnyomat.pdf',3,3,1,7,4,5,5,'2010-5-4','2010-11-15','','mestergyorgyi@freemail.hu','','Azon az éjszakán teljes átéléssel viselt, erotikus álma volt. Évek óta először. Szinte megújult tőle, frissen, felajzottan ébredt. Pedig nem is a szőke nővel álmodott. Az álmában látott női test csupán fehér bársonnyal borított, ruganyos, kemény hús volt, melyben úgy merült el, mint légy a tejben. Élvezettel… de semmi több. Ettől ébredt jóllakottan, kielégülten. Az éjjel átélt élmény azontúl hatással volt a mindennapjaira is. Magában gyakran fohászkodott, legyen szerencséje, csak picurka szerencséje, hogy legalább egy pillantás erejéig, ismét láthassa az asszonyt. A látványt akarta magába szívni, elraktározni, hogy megéljen belőle a következő találkozásig. De vajon találkozásnak nevezhető az olyan együttlét, amelynek egyoldalúan, csupán ő a részese?!
INSERT INTO "books" VALUES(NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,3,13,'http://books.google.hu/books?printsec=frontcover&id=Jr2VaVuG16AC#v=onepage&q=&f=false',1,'',20,20,'','','','','','',0,'',15,11,2010,410,'Vasi Szabó János','Világállam','978-615-5014-93-2',2,'','2','','','0',990,6,'','Vasi-Szabo-Janos','','','','','','','','',3,3,1,7,4,5,3,'2009-11-0','2010-11-15','06-94 -711-108','vasi.szabo.janos@gmail.com','','A Világállam helyszínei különbözőek: a Mars rideg homokja, a galaxis mélyén rejtőző civilizáció, klausztrofóbiás fémburok-otthon, zöld planétánk alternatív valósága, a mediterránum hőségtől szenvedő kőtáblái.
INSERT INTO "books" VALUES('',0,'','','','',0,0,0,13,'http://books.google.hu/books?printsec=frontcover&id=-fSxn4GFeWIC#v=onepage&q=&f=false',1,'',20,20,'','','','','','',0,'',15,11,2010,411,'Vasi Szabó János','Csillagpuszta','978-615-5014-92-5',2,'','3','','','0',790,6,'','Vasi-Szabo-Janos','','http://bookline.hu/product/home!execute.action?id=81297&type=22&_v=Vasi_Szabo_Janos_Csillagpuszta','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/csillagpuszta','','','','',3,3,0,7,4,0,0,'2009-3-0','2010-11-15','Vasi Szabó János, 94/711-108, 9762 Tanakajd, Kossuth L. u. 26.','vasi.szabo.janos@gmail.com','','Az első két történet a Világállamban játszódó disztópia. A  Haszontalan mágia főszereplője a szürke kishivatalnokként élő Jim Scone: kezébe kerül egy ősrégi recept. A vegyület felszabadítja az ember mentális képességeit. Scone képes lett a múltba pillantani. Így kiderítette, hogy ki erőszakolta meg brutálisan a komputerosztály csinos, fiatal alkalmazottját, aki emiatt öngyilkos lett. Ám hiába a különleges képesség, a nyomozók őt tartják tettesnek és elmegyógyintézetbe csukják.
