INSERT INTO "books" VALUES(2990,0,'','Bohm_Edit--Versszavalas--FD.jpg',518,2,1,0,0,41,'',0,'',0,0,'',15,5,794,100,'',1,'',2,4,2009,418,'Böhm Edit','A magyar versszavalás története','978-963-9888-93-7',2,'','2','140x200 mm',428,'0',3990,3,'#LA2,LG28# ->§93 saját haszonra újranyomás','Bohm-Edit','http://www.konyvesbolt.online/spd/978-963-9888-93-7/Bohm-Edit-A-magyar-versszavalas-tortenete-Ad-Libru','http://bookline.hu/product/home!execute.action?id=79731&type=22&_v=Bohm_Edit_A_magyar_versszavalas_tortenete','','','http://www.konyvesbolt.online/spd/978-963-9888-93-7/Bohm-Edit-A-magyar-versszavalas-tortenete-Ad-Libru','','','',3,3,1,9,4,5,1,'2009-2-0','2009-4-2','Némethné Dr. Böhm Edit 70/37-47-282,23/379-564, 2030 Érd, Betonozó u. 15.','edi05@t-online.hu','A magyar verselőadás, versszavalás gyökerei, hagyományai és fejlődésének küzdelmes útja.','Ez a könyv a magyar verselőadás (versszavalás) gyökereit, hagyományait, fejlődésének küzdelmes útját, fontosabb állomásait tárja fel, amivel hozzájárul e művészeti ág vitatott kérdéseinek megválaszolásához. Egyben emléket állít azoknak a képviselőinek, akik a különböző korszakokban hittel és odaadással vállalták fel a költészet élőszóbeli közvetítését, de mert művészetük –a színészethez hasonlóan- a pillanat művészete, alakjuk gyorsan eltűnik az emlékezetből. Bemutatja a versek szavalásával kapcsolatos nézetek, elméletek alakulásának folyamatát és utal az egyes korszakok előadóművészeti közegére, sajátos elvárásaira, az irodalmi- és a színházi élettel való összefüggésekre.
INSERT INTO "books" VALUES('',0,'','Arany_Emmi-FD.jpg',137,'',1,0,18,15,'',0,'',40,40,'','',20,259,'',400,0,'',0,11,2008,419,'Arany Emmi','Ti, kínaiak','978-963-9888-50-0',2,'','1','140x200 mm',106,'0',1990,1,'#LA6; LGIII,IV#->§94 T&B:szerző','Arany-Emmi','http://www.konyvesbolt.online/spd/978-963-9888-50-0/Arany-Emmi-Ti-kinaiak-Ad-Librum-2008','http://bookline.hu/product/home!execute.action?id=77513&type=22&_v=Arany_Emmi_Ti_kinaiak','','','','','','',3,0,0,0,0,0,0,'Array-0-0','2008-11-0','Vincze Edit, 20/94-29-037, ideiglenes: megszünt, állandó: 1137 Budapest Szent István krt. 30.','vincze@emimail.com','Egy ösztöndíjas kalandjai Kínában.','﻿„A változás, az, hogy semmi nem állandó, erre az országra egyértelműen jellemző. Tulajdonképpen ez volt az egyik fő oka, amiért ezt a könyvet megírtam. Szeretném, ha minél többen megismernék az itt élő emberek igazi arcát. A boldogságukat, a könnyeiket, örömüket, bánatukat. Kicsit bepillantanának a mindennapi életükbe, és ezzel közelebb kerülnének ehhez a túlmisztifikált világhoz. Én megszerettem őket. A hibáikkal, rossz tulajdonságaikkal együtt.  Mégis, szívemből szólnak ők, az első perctől fogva. Mert adtak nekem valamit, valamit önmagukból, abból a szemléletből, ahogy ők látják a világot. Sok mindenre tanítottak, és remélem én is hagytam magamból valamit az ő számukra.
INSERT INTO "books" VALUES('',0,'','Pozsgai_Zsolt-FD.jpg','',3,1,0,0,1,'http://books.google.hu/books?printsec=frontcover&id=fRv5fQfs8A8C#v=onepage&q=&f=false',0,'',40,40,'',100,20,350,1000,1000,2,'',0,11,2008,420,'Pozsgai Zsolt','Szeretlek, fény - történelmi játékok, társadalmi drámák, bohózatok','978-963-9888-53-1',2,'','1','140x200 mm',368,'0',2990,1,'#LGrégi salgó# D ->§97 T:G,B:V','http://adlibrum.hu/Pozsgai-Zsolt/','http://www.konyvesbolt.online/spd/978-963-9888-53-1/Pozsgai-Zsolt-Szeretlek-feny---tortenelmi-jatekok-','http://bookline.hu/product/home!execute.action?id=76861&type=22&_v=Pozsgai_Zsolt_Szeretlek_feny','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/vers_drama/szeretlek_feny_tortenelmi_jatekok_tarsadalmi_dramak_boh','http://www.konyvesbolt.online/spd/978-963-9888-53-1/Pozsgai-Zsolt-Szeretlek-feny---tortenelmi-jatekok-','','','',3,0,0,0,0,0,0,'2008-10-0','2008-11-0','ideiglenes: 1021 Budapest, Hüvösvölgyi u.6. 30-279-1324','pozsgaizsolt@vipmail.hu','Vak Béla, Mátyás király, Janus Pannonius, Balog úr a nyolcadik kerületből, egy tucat közép-amerikai prostituált, nagyhangú olasz család, klasszikus francia bohózati alakok...','Vak Béla, Mátyás király, Janus Pannonius, Balog úr a nyolcadik kerületből, egy tucat közép-amerikai prostituált, nagyhangú olasz család, klasszikus francia bohózati alakok mind megférnek ebben a kötetben. Pozsgai Zsolt (1960) legújabb drámakötete a műfaji sokféleség jegyében született. Megtalálható itt érzékeny történelmi színmű, abszurd komédia, társadalmi dráma, bűnügyi játék, és két, álnéven írt bohózat. A szerző egész eddigi életműve a műfaji sokrétűséget képviseli. Eredeti darabjaival, musical-szövegkönyveivel, vagy színpadi átdolgozásaival gyakran találkozhatunk a színházakban. Nem csak itthon, egyre gyakrabban külföldön is. A kötetben található művek egy kivételével már kiállták a színpad próbáját, nagy sikerrel mutatták be, és játszották, vagy játsszák ma is őket. Olvasva is élvezetes  és kitűnő szórakozást nyújtanak.','A ki nem fizetett tételek miatt visszafogott könyvek helye.',1225098412,1451300819,0);
INSERT INTO "books" VALUES(1990,0,'','Szabo_Erika--Tunetmagyarazo--FD.jpg',317,0,1,0,0,30,'http://books.google.hu/books?printsec=frontcover&id=m1PxXkCoN50C#v=onepage&q=&f=false',1,'',40,40,'','',5,282,'','',0,'',20,3,2009,421,'Dr. Szabó Erika','Házi tünetmagyarázó - Fejfájás, hasi fájdalom, láz, lapozza fel, mi okozhatja','978-963-9888-76-0',2,'','2','A5',232,'0',2490,1,'#LB6, LGIII#->§125','Dr-Szabo-Erika','http://www.konyvesbolt.online/spd/978-963-9888-76-0/Dr--Szabo-Erika-Hazi-tunetmagyarazo---Fejfajas-has','http://bookline.hu/product/home!execute.action?id=79712&type=22&_v=Szabo_Erika_dr_Hazi_tunetmagyarazo','','http://www.fo.hu/hu/konyv/szakkonyv/orvosi/hazi_tunetmagyarazo_fejfajas_hasi_fajdalom_laz_lapozza_fel_mi_okozh','http://www.konyvesbolt.online/spd/978-963-9888-76-0/Dr--Szabo-Erika-Hazi-tunetmagyarazo---Fejfajas-has','','','',3,0,0,7,4,0,0,'Array-0-0','2009-3-20','','drszabo@mhcable.com','Fejfájás, hasi fájdalom, láz - Lapozza fel, mi okozhatja!','Tüneteket, szervezetünk jelzéseit minden nap tapasztaljuk valamilyen formában. A tünetek, bár sok esetben kellemetlenek, nagyon fontos információk  szervezetünk működéséről. A fájdalom különböző testrészekben, izgatottság, kézremegés, étvágytalanság, memóriazavarok, zsibbadás, emésztési zavarok, ájulásérzés, szaglás, ízérzet csökkenése, mind fontos jelzések, amikkel a szervezet tudtunkra adja, hogy valamilyen szervi vagy működési hiba történt. Mivel a betegség meghatározása nem egyszerű a tünetekből, kezdő nővér koromban elkezdtem egy gyorsan átlátható diagnosztikai szerszám összeállítását, amit az egyetemi évek során bővítettem, és most megosztok önnel. A tünetek, tünetcsoportok listája gyors áttekintést ad például a lázat okozó betegségek okaira, mik okozzák, ha kísérő tünetként  fejfájás, köhögés, hányinger, szédülés, duzzadt nyirokcsomó, bőrkiütés társul hozzá. Milyen betegségek okozhatnak hasi fájdalmat, mik lehetnek a kiváltó okok amikor a hasi fájdalmakat láz, fejfájás, hányinger kíséri. Célom nem a laikus öndiagnosztika elősegítése, hanem az ön és orvosa közreműködésének megkönnyítése. Minél tájékozottabb a páciens, annál pontosabban képes tüneteit elmondani, aminek következménye a tünetet kiváltó okok gyorsabb megállapítása és kezelése. A könyvben szintén talál információt számos betegség tüneteinek rövid ismertetéséről, a betegellátásban, gyógyszer és gyógynövényhasználatban előforduló hibákról és betegségek kialakulásának megelőzéséről, valamint kevésbé ismert tünetekről, az öregedés folyamatának lassításáról. ','312 g.',1229337902,1451384402,0);
INSERT INTO "books" VALUES('',0,'','Kamocsay_Ildiko--Bovary_kisasszony--FD.jpg',213,'',1,0,8,4,'http://books.google.hu/books?printsec=frontcover&id=nRoMNghIsZcC#v=onepage&q=&f=false',1,'',40,40,'','',5,210,'','',0,'',4,6,2009,422,'Kamocsay Ildikó','Bovary kisasszony','978-963-9888-77-7',2,'','2','148x210 mm',152,'0',2290,1,'#LGI,LGVI, LB5#  ->§126 T:G B:V','Kamocsay-Ildiko','http://www.konyvesbolt.online/spd/978-963-9888-77-7/Kamocsay-Ildiko-Bovary-kisasszony-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=81296&type=22&_v=Kamocsay_Ildiko_Bovary_kisasszony','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/bovary_kisasszony','','','Kamocsay_Ildiko','',3,3,1,7,4,0,0,'Array-0-0','2009-6-4','','racka@monornet.hu','Vajon mi lett a sorsa a Bovary-házaspár ötévesen árván maradt kislányának, Berthe-nek.','Kamaszkoromban olvastam először a Bovaryné-t, s azóta nem hagy nyugodni, vajon mi lett a sorsa a Bovary-házaspár ötévesen árván maradt kislányának, Berthe-nek. Flaubert néhány ecsetvonása is elég volt hozzá, hogy megelevenedjék, s képes legyen megszólítani az embertársadalom tagjait. Kezdeti, még gyermekded kíváncsiságom az évek során egyre kínzóbbá vált: vajon mi lett vele? Mindinkább úgy éreztem, hogy a vérrokonságnál is szorosabb szálak fűznek hozzá, s  végül rádöbbentem: én tudom, mi lett vele!
INSERT INTO "books" VALUES('',0,'','','',0,0,2,0,21,'',0,'','','','','','','','',100,0,'',22,12,2010,423,'Dr. Sándorné Manyika','Útravalók - Bölcsességek','978-963-08-0504-9',1,'','3','110x140 mm',80,'0','',1,'#LB6#','','','','','','','','','',3,1,1,9,4,5,5,'2011-1-0','2010-12-22','dr. Sándor Györgyné, Győr, Szent István út 14/A, 20-99-26-867','manyika1941@gmail.com','','','Email cím angel8_anita@freemail.hu 2015.01.16-ig.','',1426531646,0);
INSERT INTO "books" VALUES('',0,'','',142,'',0,0,0,10,'',1,'',20,20,'','','','','','',0,'',26,9,2016,424,'Szalóczy Pál','A Vénusz-rejtély','978-615-5014-65-9',2,'','3','',142,'0',990,6,'','Venusz','','http://bookline.hu/product/home!execute.action?id=85712&type=22&_v=Szaloczy_Pal_A_Venusz_rejtely','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/a_venusz_rejtely','','http://www.alexandra.hu/scripts/cgi/webshop.cgi/GetBook?SessionID=3A034F263F57E054F89DAA02456FD1D49C3A69C90B15EEDDB4CBFC4547179E6A89F4966AEB65AA1C509AC40YVBBRTVYJECUHHCIPDIGLJYCRNHLTDNNLBC63B07C03B&TabSheet=book&Page=1&SrcWord=Szal%F3czy&SrcField=sf&SrcCategory=&CategoryID=A8F&BookID=702279&GotoBook=True&Price=&CBStock=Checked&CBDiscount=&LastDays=20','','',3,3,0,7,4,5,0,'Array-0-0','2016-9-26','1125 Bp., György Aladár u. 13. II/9. T.: 20/959-0580','szaloczypal@gmail.com','A népszerű rádiós harmadik könyvét, egy eltűnt műtárgy talányos krimijét, teljes mértékben dialógusokban írta meg.','Holtan találnak egy öreg hölgyet egy budai villában. A család nyaralt. A halál vélt oka: szívelégtelenség. Három héttel később a hölgy lánya fedezi fel, hogy ellopták Lotz Károly Vénusz című festményét a házból. A kép eltűnése rejtély. Erőszakos behatolásnak semmi nyoma, az értékes műtárgyat rejtekhelyen tartották, amelynek hollétéről csak anya és lánya tudott. A talányos történet szálainak kibogozását a legendás sakkjátékos, ám mozgássérült Őrnagy vállalja. A játszma elkezdődik...
INSERT INTO "books" VALUES('',0,'','','',0,0,0,0,16,'',0,'',40,40,'','',5,300,'','',0,'',19,10,2009,425,'Villányi Rózsa','Barátom, Cvek Edli','978-963-9934-23-8',2,'','2','210x148 mm',52,'0',1990,1,'#LB6# ->§191 utóélete, keménytábla','Villanyi-Rozsa','','http://bookline.hu/product/home!execute.action?id=84031&type=22&_v=Villanyi_Rozsa_Baratom_Cvek_Edli','','http://www.fo.hu/hu/konyv/szepirodalom/gyerekirodalom/mesek/baratom_cvek_edli','','','Villanyi-Rozsa','',5,3,0,7,4,5,0,'2009-7-2','2009-10-19','7634 Pécs, Szúnyog dűlő 1. T.: 30/403-1286','villanyi.rozsa@gmail.com','','„Elárulok egy titkot. A halhatatlanság titkát. Ha szülőként, nagyszülőként mesélünk gyermekeinknek, akkor ők arra egy életen át emlékezni fognak, és az emlékünket a mesékkel együtt generációknak adják tovább. Kérem, higgyenek nekem, anyukaként és gyermekkönyvtárosként tudom, hogy így van. A meghitt percekhez szeretettel nyújtom át Cvek Edli és Dozó történetét.”
INSERT INTO "books" VALUES('',0,'','','','',0,0,0,34,'',1,'',20,20,'','','','','','',0,'',19,10,2016,426,'Eiben Tamás','A jelszó: hatékonyság – Menedzsment útmutató az eredményes üzlethez','978-615-5686-30-6 ',2,'','9','',236,'0',1990,6,'','Eiben-Tamas','','','','','','','','',3,3,0,0,0,0,0,'2010-10-25','2016-10-19','Eiben Tamás Endre, 1086 Budapest, Szerdahelyi u. 4-8. 5/5.','tamas.eiben@yahoo.de','Végre egy valóban hasznos, a helyi viszonyokról szóló menedzsment-szakkönyv, melynek gyakorlati tanácsaival elébe mehet főnöke elvárásainak és egy csapásra eredményes vezető lehet.','- Hogyan érjük el, hogy a munkatársak felelősséget vállaljanak, és mindent megtegyenek az üzleti sikerért?
INSERT INTO "books" VALUES('',0,'','','','',0,0,0,13,'http://books.google.hu/books?printsec=frontcover&id=ZppUG9MtvxgC#v=onepage&q=&f=false',1,'',20,20,'','',5,500,'','',0,'',26,9,2016,427,'Atrox N. Teuton','Az elátkozott grófság','978-615-5014-87-1',2,'','2','','','0',1490,6,'Szeder Norbert Attila','Atrox','','http://bookline.hu/product/home!execute.action?id=82274&type=22&_v=Teuton_Atrox_N_Az_elatkozott_grofsag','','http://www.fo.hu/hu/konyv/szepirodalom/sci_fi_fantasy_krimi/az_elatkozott_grofsag','','','','',3,3,1,7,4,0,0,'2008-12-0','2016-9-26','Szeder Norbert Attila, 1203 Budapest, Ősz utca 20., 06-30-904-3465','atrox@inf.elte.hu','','Atanar a civilizációtól távol, egy gyors folyású, hegyi patak partján tér magához. Megdöbbenve tapasztalja, hogy emlékeit elvesztette, eddigi életéből semmire nem emlékszik. Ki ő? Honnan jött? Hová tart? A múlt felderítésére egyetlen esélye egy rövid levél, mely átázva kerül elő mellénye zsebéből. Ennek nyomán elindul, hogy felderítse múltját, ám hamarosan megtapasztalja, hogy ez nem olyan egyszerű dolog. Útja során számtalan ellenséget, akadályt kell leküzdenie, mert ez a világ veszélyes, és a gyengék nem sokáig élnek. Azonban értékes barátokra is szert tesz kalandozásai során. És közben egy percre sem felejti el célját: felkutatni elveszett múltját. A nyomok végül egy távoli grófságba vezetnek, ahol furcsa dolgok történnek…','2016-09-21: ISBN átvéve a Támadás c. meghiúsult könyvről.','',1474885835,0);
INSERT INTO "books" VALUES('',0,'','Gigi_Scott--Sarkany_szuletik--FD.jpg',244,'',1,0,16,13,'',1,'',40,60,'','','','','',100,0,'',1,10,2009,428,'Gigi Scott','Sárkány születik - A gyermek','978-963-9934-27-6',2,'','2','140x200 mm',200,'0',1990,1,'#LE,LG27# ->§199; Faragó Ágnes','Gigi-Scott','http://www.konyvesbolt.online/spd/978-963-9934-27-6/Gigi-Scott-Sarkany-szuletik---A-gyermek-Ad-Librum-','','','','','','','',3,3,0,7,4,5,0,'2009-7-0','2009-10-1','Faragó Ágnes Julianna, 20/575-9544','a.j.farago@gmail.com','Egy különös kislány, Diana története, akinek élete egy távoli világban történtekkel áll kapcsolatban.','A Sárkány születik egy különös kislány, Diana története. Egészen a fogantatásától kezdve szokatlan dolgok történnek körülötte, amiket az idő előrehaladtával a környezete – különösen az édesanyja – egyre rosszabbul visel. Diana azonban egy gyermek őszinte érdeklődésével fordul a szokatlan lények és események felé. Ám ezek a kezdeti szórakoztató kalandok szinte észrevétlenül fordulnak egyre komolyabbra, mindaddig, amíg már a kislány élete is veszélybe kerül. Diana kalandjai során a személyisége is sokat változik, és csakhamar rájön, hogy az események egy távoli világban történtekkel állnak kapcsolatban, amelyekhez neki is köze van valamiféleképp.
INSERT INTO "books" VALUES('',0,'','Goczi_Noemi--Az_elet_arnyekaban--FD.jpg',98,'',1,0,0,4,'',1,'',40,60,'','',5,160,'',125,0,'',10,7,2009,429,'Góczi Noémi','Az élet árnyékában','978-963-9934-16-0',2,'','2','A5',60,'0',1990,1,'#LB7# ->§183','Goczi-Noemi','http://www.konyvesbolt.online/spd/978-963-9934-16-0/Goczi-Noemi-Az-elet-arnyekaban-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=82023&type=22&_v=Goczi_Noemi_Az_elet_arnyekaban','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/az_elet_arnyekaban','','','','',3,3,0,7,4,0,0,'2009-6-0','2009-7-10','7145 Sárpilis, Dózsa u. 18. Tel.: 20/389-2201','nonyka90@freemail.hu','','A könyv, amelyet a kedves Olvasó a kezében tart, több nem mindennapi témát dolgoz fel történetszerűen. Ezek: skizofrénia, gyermeki félelmek, kéjgyilkosság – egyre inkább társadalmunk hozadékává válnak. Nem mindannyiunknak alakul ki közvetlen kapcsolata ezekkel a dolgokkal, de egyre többen vagyunk kénytelenek közvetetten találkozni velük újságok, TV-s közvetítések által, ezért érdemes és kell is foglalkoznunk velük, ha csak addig is, míg ezt a néhány rövid novellát végigolvassuk.
INSERT INTO "books" VALUES('',0,'','Fulop_Beata--Adela--FD.jpg','','',1,0,4,12,'',1,'',40,40,'','','','','',250,0,'',25,5,2011,430,'Fülöp Beáta','Adela - Az álmok útján','978-615-5110-01-6',2,'','4','148x210 mm',220,'0',2490,1,'#LB6# RA1','Fulop-Beata','http://www.konyvesbolt.online/spd/978-615-5110-01-6/Fulop-Beata-Adela---Az-almok-utjan-Ad-Librum-2011','','','','','','','',3,3,1,7,4,5,5,'2010-11-0','2011-5-25','30/260-1653 1185 Bp., Zilah u. 66.','dolcespiritoso71@yahoo.com','','Asad, az arab herceg és Adela, az európai hastáncosnő története egy igazán varázslatos, felnőtteknek szóló sivatagi mese, egy egzotikus és misztikus kaland az álmokból a valóságba, és onnan vissza. Egy látszólag könnyed, de mégis viszontagságokkal teli utazás a szerelemért, amelyet át meg átfúj a szenvedély forró szele, és amely nincs távol a képzelet szülte helyszínektől sem, amelyek épp oly valóságosnak tűnnek, mint a lány álmaiban felbukkanó férfi, aki hús-vér alakban is megmutatja magát szerelme előtt. 
