INSERT INTO "books" VALUES('',0,'','Endridi_Skalli--Amit_Odin_sugott--FD.jpg',469,'',1,0,0,8,'http://books.google.hu/books?printsec=frontcover&id=YOVK11iiVBMC#v=onepage&q=&f=false',0,'',0,0,'','','','','','',0,'',20,11,2009,453,'Endridi Skalli','Amit Ódin súgott','978-963-9934-45-0',2,'','2','140x200 mm',400,'0',2990,1,'#LD# §218 duplikátuma T:G,B:szerző Dr. Kolozs Balázs.','Skalli','http://www.konyvesbolt.online/spd/978-963-9934-45-0/Endridi-Skalli-Amit-Odin-sugott-Ad-Librum-2009','http://bookline.hu/product/home!execute.action?id=85372&type=22&_v=Skalli_Endridi_Amit_Odin_sugott','','http://www.fo.hu/hu/konyv/szepirodalom/felnottirodalom/regenyek/amit_odin_sugott','','','','Endridi_Skalli',3,3,0,7,4,5,5,'2009-9-28','2009-11-20','Dr. Kolozs Balázs, 30/241-7164, 1143 Budapest, Hungária krt. 97. IV/1.','kolozsbalazs@gmail.com','Történelmi regény a középkori Grönlandról.','A XIV. századi Grönland világtól elzárt skandináv településein a vikingek kora még nem ért véget. A tűzhelyek parazsa mellett régi-új mesék kapnak szárnyra elfeledett istenekről, valamint pogány regékből ismert, a part mögötti jégmezőkön megbúvó rettentő szörnyekről. E messzi északon lankadatlan harc folyik a kegyetlen természet erőivel, az inuitokkal, hataloméhes, gátlástalan földbirtokosokkal, miközben az egyház is felveszi kilátástalan küzdelmét a pogányság terjedése ellen. A körülmények összjátéka végletes jellemeket formál: vak kapzsiságot, önzést, bátorságot és önfeláldozást.
