INSERT INTO "books" VALUES('',0,'','Czako_Eva--Telihold--FD.jpg',163,'',1,0,0,12,'',1,'',15,30,'',50,NULL,NULL,500,500,2,NULL,27,5,2011,457,'Czakó Éva','Telihold – Csillámok és Ádámságok','978-615-5110-10-8',2,'','4','130x200 mm',140,'0',1690,2,'#LB6,LGsalgó#  Buza Ágnes Kinga, K:K,T:G.B:B','Czako-Eva','http://www.konyvesbolt.online/spd/978-615-5110-10-8/Czako-Eva-Telihold-Csillamok-es-Adamsagok-Ad-Libru','','','','','','','',3,3,4,7,4,5,5,'2011-3-0','2011-5-27','30/475-1923,6600 Szentes, dr Uhlár I. u.1','czako.evi@gmail.com','Könnyű nyári flört, tánc, versengés, váratlan találkozás és búcsúzás, titkok és lebukások, míg végül egy teliholdas éjjelen kisimul minden.','Ádámmal, a sármos álom-pasival és Csillával, a temperamentumos csajjal (aki mellesleg Ádám egyetlen és kedvenc húga) a naplóbejegyzéseiken keresztül ismerkedünk meg. Egy közös nyaralás, és összegabalyodnak a szálak: új barátok, könnyű nyári flört, tánc, versengés, váratlan találkozás és búcsúzás, titkok és lebukások, míg végül egy teliholdas éjjelen kisimul minden. Szakítások, kibékülések, viták és hallgatások, új és régi barátok, vidámság és tragédia. És ismét telihold.
