INSERT INTO "books" VALUES('',0,'','SolutionSurfers--Brief_Coaching--FD.jpg','',0,1,0,0,34,'',0,'',40,70,'','','','','',500,0,'',19,5,2014,527,'Chris Iveson, Evan George, Harvey Ratner','Brief Coaching. Megoldásközpontú megközelítés','978-963-08-9075-5',3,'SolutionSurfers Magyarország Kft.','7','135x200 mm',224,'0','',1,'#B2 SolutionSurfers B&T:B','Coaching','','','','','','','','',3,3,1,9,4,5,4,'2014-3-31','2014-5-19','SolutionSurfers Magyarország Kft., 1222 Budapest, Lőcsey u. 6/A., 20/421-8300, +41 79 432 2108','info@handlungsspielraeume.com','','„A coaching eleganciájáról és szépségéről írt talán legforradalmibb jelenleg kapható könyv. A szerzők mintegy 30 év tapasztalatát sűrítették a könyvbe, az olvasó kezébe helyezve a coaching esszenciáját. Könnyed és kellemes olvasmány, ugyan akkor elgondolkodtató és egyben gyakorlatias. Az olvasó könnyen azon kaphatja magát, hogy a javasolt kérdéseket, megfogalmazásokat akár már a következő coachingbeszélgetésében is alkalmazza, hiszen vonzók és zseniálisak. Ráadásul lenyűgöző, hogy egészen rövid idő alatt milyen tartós változásokat eredményeznek. Hihetetlen? Olvassa el, és tanuljon a legjobbaktól! Hasznos olvasást!”
