INSERT INTO "books" VALUES('',0,'','Horvath--Lovasz--A_megsemmisules--FD.jpg','','',1,0,0,4,'',1,'',10,10,'','',NULL,NULL,'',300,0,NULL,24,3,2017,533,'Horváth Márk és Lovász Ádám','A megsemmisülés','978-615-5686-79-5',2,'','10','140x200 mm',288,'0',2990,1,'','','http://www.konyvesbolt.online/Horvath-Mark-es-Lovasz-Adam-A-megsemmisules-Ad-Lib','','','','','','','',2,3,4,7,4,4,3,'2017-2-0','2017-3-24','adam.lovasz629@yahoo.com; Horváth Márk 9700 Szombathely, Nádasdy F. u. 7., 30/683-3111; Lovász Ádám 2119 Pécel, Kölcsey u.10., 70/264-8206','purplemark@hotmail.com','','A megsemmisülés rejtélyes szövege egyszerre filozófiai traktátus, misztikus beavatás és poszthumán próza. A kortárs irodalomban egyre inkább felerősödik ez a nem-antropocentrikus hang, mely nem emberi sorsokat akar elbeszélni, hanem a nyelv és az ember közös hiánytörténetére mutat rá. „Mennyien kapaszkodtak a létbe, mint egy végtelen fa törzsébe” - írja Horváth Márk és Lovász Ádám, hiszen az emberi állapot csak a társadalmi, nyelvi és metafizikai katasztrófa terében értelmezhető. Apokaliptikus (neo)romantika és abszurd költészet. Az utolsó ember kézikönyve a túlélés lehetetlenségéről. 
