INSERT INTO "books" VALUES('',0,'','Babos_Lajos--Az_elso_aradi_vertanu--FD.jpg',150,'',1,0,0,39,'',1,1393,15,15,'','',NULL,NULL,'',300,1,NULL,7,6,2016,578,'dr. Babós Lajos','Az első aradi vértanú. Tények és dokumentumok Ormai Norbert életéről','978-615-5110-87-0',2,'','9','140x200',100,'0',1990,1,'#LD#','','http://www.konyvesbolt.online/dr--Babos-Lajos-Az-elso-aradi-vertanu--Tenyek-es-d','','','','','','','',3,3,1,7,4,5,5,'2016-4-29','2016-6-7','dr. Babós Lajos, (30) 279-5779; 1119 Bp. Etele u. 8.','dr.babos.lajos@gmail.com','Az egykori ezredes, Ormai Norbert életét és halálát máig legendák övezik. Sokan, még a neves történészek is, minden komolyabb utánajárás nélkül nevezték szélhámosnak. E kiadvány megpróbálja tisztázni az Ormaival kapcsolatos félreértéseket, torzításokat. ','Ormai Norbert Kossuth Lajos mellett szolgált, s remek meggyőzőképességével ötezer vadászkatonát állított a szabadságharcba. Gyorsan tört előre, az 1848 júliusában még hadnagyi rangban szolgáló Ormait tíz hónap múlva már ezredessé léptették elő, Kossuth kinevezte a honvéd vadászezredek főfelügyelőjévé. Pár nappal azután, miután visszavonult és lemondott beosztásáról, császári fogságba esett, majd a hadbírósági tárgyalása napján kivégezték.
INSERT INTO "books" VALUES('',0,'','Nicholas_Shear--Szornyu_Almos_tizedes_kalandjai--FD.jpg',226,'',1,0,0,20,'',1,1743,0,0,'',75,NULL,NULL,300,320,1,NULL,14,9,2016,579,'Nicholas Shear','Szörnyű Álmos tizedes kalandjai','978-615-5110-94-8',2,'','9','140x200 mm',160,'0',2490,2,'Nyíri Miklós #LE#','','http://www.konyvesbolt.online/Nicholas-Shear-Szornyu-Almos-tizedes-kalandjai-Ad','','','','','','','',3,3,4,7,4,5,1,'2016-7-0','2016-9-14','Nyíri Miklós, 1135 Bp. Petneházy u. 61-63/B., tel: 06-30-523-6035','nyirimiklos@gmail.com','Defektes detektívek, avagy a makói móka...','A Magyar Rendőrség különlegesen elit alakulatának hat fős szupercsapata nem mindennapi megbízást kap és mindent megtesznek annak érdekében, hogy sikerre vigyék küldetésüket.
