INSERT INTO "books" VALUES('',1,'','Matthew_Vigo--Mystery_in_Noir--FD.jpg',310,'',1,0,0,10,'',1,'','','','','',NULL,NULL,'',100,0,NULL,2,11,2016,606,'Matthew Vigo','Mystery in Noir','978-615-5686-27-6',2,'','9','130x200 mm',240,'0',1990,1,'#LE#','','http://www.konyvesbolt.online/Matthew-Vigo-Mystery-in-Noir','','','','','','','',3,3,1,7,4,5,3,'2016-9-21','2016-11-2','Száray Mátyás, 1119 Bp. Etele út 69. 8/77., tel: 30/857-4471','mszaray@yahoo.com','','One day – actor-turned-detective – Anthony Noir receives a letter from California, in which an old lady asks his help in the investigation of a long-ago case. On New Year’s Eve 1929 a famous Hollywood actress died in a car accident. The mysterious client implies it was – in fact – a deliberate murder.
