INSERT INTO "books" VALUES('',0,'','','','',0,0,5,2,'',1,'','','','','',NULL,NULL,'','',0,NULL,25,9,2016,615,'Bagi István (szerk.)','Amerikai költők a második ezredfordulón','978-615-5686-17-7',2,'','9','',240,'0',1390,6,'','','','','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2016-9-25','Dr. Bagi István, 3300 Eger, Almagyar u. 12., 36/787 889, 20/354 3697, 30/906 0022','bagiistvandr@gmail.com','Válogatás kortárs amerikai költők verseiből. Kétnyelvű antológia  verskedvelő olvasóknak, egyben hasznos kötet az angol nyelvvel ismerkedőknek is.','A fordító huszonöt amerikai költő összesen százegy versét válogatta kétnyelvű antológiába. Olyan költők verseit, akik kortársaink a második ezredforduló tájékán. Igyekezett színes képet kapni – és mutatni – a magyar irodalomkedvelőknek híres költők változatos egyéniségéről, témájuk kavalkádjáról.
