INSERT INTO "books" VALUES('',0,'','','','',0,0,0,3,'',1,'','','','','',NULL,NULL,'','',0,NULL,26,9,2016,619,'Puskás Dezső','Egyedül a dzsungelben','978-615-5686-23-8',2,'','8','',88,'0',900,6,'','','','','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2016-9-26','id.cím: 2800 Tatabánya, Akácfa u. 8., állandó: ~ Katona J. u. 7/1., tel: 06-20-250-1554','puskasde@gmail.com','Novellák az emberi lélek és emberi szellem bárgyúságáról szomorú képekkel, iróniával és néhol gúnyos humorral.','Egy novelláskötetet tart a kezében a Tisztelt Olvasó. Bár a kötet kifejezés nem pontos, hiszen eme prózai művek tematikailag nem teljesen alkotnak egy egész képet. Vannak azonban összefüggések az írások között, hiszen mindegyik a hétköznapi élet világát ábrázolja az író szemszögéből. Szomorú képekkel, néhol gúnyos humorral, iróniát sem nélkülözve mutatják be az emberi lélek és emberi szellem bárgyúságát.
INSERT INTO "books" VALUES('',0,'','','','',0,0,0,43,'',1,'','','','','',NULL,NULL,'','',0,NULL,30,10,2016,620,'Jenő Kontschán et al.','New data to the mite fauna of the Korean Peninsula','978-615-5686-20-7',2,'','9','',93,'0',1250,6,'','','','','','','','','','',2,3,0,0,0,0,0,'Array-0-0','2016-10-30','Dr. Kontschán Jenő, 30/768-6927','jkontschan@gmail.com','This book contains the first records of 25 mite species from the Korean Peninsula.','This book contains the first records of 25 mite species from the Korean Peninsula. Five mite species are found on the body of insects (bees and scrabeoid beetle) and 17 soil dwelling Mesostigmata are presented as new species from the Korean Peninsula. New occurences of 10 earlier recorded Mesostigmatans and a second data of a plant inhabiting spider mite are presented as well.','',NULL,1474656444,0);
