INSERT INTO "books" VALUES('',0,'','','','',0,0,3,21,'',1,'',0,0,'','',NULL,NULL,'','',0,NULL,17,10,2016,638,'Dr. Sáry Gyula','Üres helyek trófeái','978-615-5686-37-5',2,'','9','',320,'0',1450,6,'','','','','','','','','','',3,3,0,0,0,0,0,'Array-0-0','2016-10-17','','','Filozófikus eszmefuttatások erdőről, madarakról, fegyverekről, vadászírókról és veszendő értékekről.','Csak szenvedélyes erdőjáróknak!
INSERT INTO "books" VALUES('',0,'','','','',0,0,0,3,'',1,'','','','','',NULL,NULL,'','',0,NULL,30,10,2016,639,'Mester Györgyi','Fehéren, feketén - válogatott novellák','978-615-5686-38-2 ',2,'','9','',206,'0',995,6,'','','','','','','','','','',2,3,0,0,0,0,0,'Array-0-0','2016-10-30','2092 Budakeszi, Ifjúság u. 2., 23/451-617','mestergyorgyi@freemail.hu','','Egészen más ember az, akinek bensőjét örökké a tűz égeti, s mardossa a vágy. És valóban, ő, a Férfi ilyen volt. Égetnivalóan csalárd, csalfa és hűtelen, és ha nem is azért, de annak ellenére, szerették. És sokan szerették, vagy megkapni szerették volna. Tulajdonképpen mindegy is volt az, csak szóba álljon, évődjön velük, hozzájuk érjen azzal a hosszú ujjú, férfiasan elegáns kezével. Simítsa a karjukat, karolja a vállukat, futólag, mintegy véletlenül érintse derekukat, hajoljon a nyakuk felé, elhitetve velük, hogy akár egy leheletnyi csók is megeshet…jobb híján elegendő volt egy átható, jelentőségteljes pillantás, vagy egy mély meghajlással kísért találó, érzékletes, olykor csupán csipkelődő bók. Odavoltak érte a nők, és ő tudta ezt. Tudatosan, vagy tudattalanul, de vissza is élt vele. Udvarolt és potyázott, ahol csak tudott. Alig akadt nő a kisvárosban, akinek ne lett volna valamiféle élménye vele. De ezen túl is, az elszegényedett, de magára még sokat adó... fiatal férfi feltűnő jelenség lévén, gyakran szerepelt a helyi lapok címoldalán, és nem csak a nőügyei miatt. 
INSERT INTO "books" VALUES('',0,'','','','',0,0,0,3,'',1,'','','','','',NULL,NULL,'','',0,NULL,30,10,2016,640,'Mester Györgyi','A LEGJAVÁBÓL - válogatott novellák','978-615-5686-39-9  ',2,'','9','',200,'0',995,6,'','','','','','','','','','',2,3,0,0,0,0,0,'Array-0-0','2016-10-30','2092 Budakeszi, Ifjúság u. 2., 23/451-617','mestergyorgyi@freemail.hu','','Szerette a tengert. Olyan fájdalmasan szép volt a látvány. Szemében visszatükröződött a lenyugvó nap tüze, mely lángoló vörösre festette a tenger azúr fényét, majd a hanyatló nap belebukott a végtelenbe, és a nagy víz kioltotta a tüzet. Ezt csodálta minden este, s a csendet, mely telítve volt a nászukat ülő kabócák örökös cirpelésével, a tenger mormogásával, a partra csapódó hullámok halk, egyenletes neszével, s a szelídülő langy fuvallat érzéki susogásával.
INSERT INTO "books" VALUES('',0,'','','','',0,0,0,38,'',1,'','','','','',NULL,NULL,'','',0,NULL,30,10,2016,641,'Mészáros Ádám','A bűncselekmény elkövetői. Elméleti és gyakorlati alapkérdések','978-615-5686-40-5 ',2,'','9','',332,'0',1450,6,'','','','','','','','','','',2,3,0,0,0,0,0,'Array-0-0','2016-10-30','','meszaros@okri.hu','','A szerző az anyagi büntetőjog egy fontos területét tekintélyes szakirodalmi anyag alapján és önálló szempontok szerint dolgozta fel.‭
INSERT INTO "books" VALUES('',0,'','','','',0,0,37,35,'',1,'','','','','',NULL,NULL,'','',0,NULL,30,10,2016,642,'Boronkai Dóra','Bevezetés a társalgáselemzésbe','978-615-5686-41-2  ',2,'','9','',200,'0',1450,6,'','','','','','','','','','',2,3,0,0,0,0,0,'Array-0-0','2016-10-30','30/848-6445 (régi: 70/279-9889) Új cím: 7030 Paks, Tolnai u. 6/b.','boronkaidori@freemail.hu','Mitől válnak érthetővé a mindennapi társalgások összecsapott, hibás szerkezeteket tartalmazó, rögtönzött szövegfoszlányai?','Mitől válnak érthetővé a mindennapi társalgások összecsapott, hibás szerkezeteket tartalmazó, rögtönzött szövegfoszlányai? Miért nem akadályozzák meg a hibák és hibajavítások a spontán beszélgetések megértését, és hogyan segítik szerveződésüket? Milyen mentális folyamatok és interakciós szabályok lépnek működésbe a hétköznapi nyelvi tevékenység során? A fentiekhez hasonló kérdésekre választ keresve a szerző egy olyan tudományág bemutatására tesz kísérletet, amelynek átfogó ismertetése magyar nyelven eddig még nem jelent meg. Az első fejezetekben számba veszi a társalgáselemzés előzményeit, alapfogalmait, főbb kutatási területeit, majd bemutatja az elemzés módszertani lépéseit és alkalmazási lehetőségeit. A könyv a külföldi szakirodalom és a hazai empirikus kutatások eredményeit ötvözi, megállapításait saját gyűjtésű, beszélt nyelvi szövegkorpuszból származó példák segítségével támasztja alá. A szerző a Pécsi Tudományegyetem Illyés Gyula Főiskolai Karának adjunktusa, számos spontán nyelvhasználattal foglalkozó publikáció szerzője. Doktori disszertációját a társalgások szövegtani jellemzőiről írta kognitív nyelvészetből. A gazdag nyelvi példaanyaggal illusztrált könyv a témához kapcsolódó kutatómunkájának szintézise, amely hasznos módszertani segítséget nyújthat a spontán nyelvhasználat további empirikus vizsgálatához, hiánypótló összefoglaló és oktatási segédanyag lehet a felsőoktatásban, és ajánlható mindazoknak, akik többet szeretnének tudni a hétköznapi, spontán helyzetekben történő kommunikációról.','',NULL,1474973815,0);
INSERT INTO "books" VALUES('',0,'','Pinter_Zoltan--Vetkozo_lelkek--FD.jpg',360,'',1,0,30,26,'',1,'',40,40,'','',NULL,NULL,'',300,0,NULL,18,11,2016,643,'Pintér Zoltán','Vetkőző lelkek','978-615-5686-11-5',5,'','9','130x200 mm',300,'0',2990,1,'#LE,LB7#','','http://www.konyvesbolt.online/Pinter-Zoltan-Vetkozo-lelkek-Expert-Books-2016','','','','','','','',3,3,4,7,4,5,3,'Array-0-0','2016-11-18','1119 Budapest, Nándorfejérvári út 29-31. A. lépcsőh. II/2.; tel:20/359-2970','zoltan.pinter07@gmail.com','A Vetkőző lelkek pszichológiai tanácsadó könyv, amelyben a terapeuta szerző önmagát is kiadja. Az irodalmi igényű kötet nem feladatokat ad; a célja inkább rávezetni klienseit (és az olvasókat), hogyan nőhetik ki problémáikat, legyen az önbizalomhiány, félelmek és gátlások, bemagolt életparancsok, kapcsolati hiányok és nehézségek vagy éppen sorsformáló döntési dilemmák.','Az élet tanításához régen sok bölcseletet írtak ún. szútra stílusban. Ennek a lényege az volt, hogy ha valamit hat szóval el lehet mondani, akkor csak ötöt mondott el. 
