INSERT INTO "books" VALUES('',0,'','Dobrossy_Rita--Elmenni_messze--FD.jpg','','',0,0,0,4,'',1,'',0,0,'','',NULL,NULL,'','',0,NULL,0,0,2008,650,'P. Dobrossy Rita','Elmenni messze..',' 978-615-5686-47-4 ',2,'','5','',361,'0',990,6,'','','','','','','','','','',2,3,0,0,0,0,0,'Array-0-0','Array-0-0','Pásztorné Dobrozsi Rita, 4600 Kisvárda, Rétalja út 1. 45/421-051','dobrozsirita@freemail.hu','','A könyv négy kisregényt tartalmaz, amelyek címéhez - éppen úgy, mint az első kisregényhez – a Kormorán zenekar dalai adták az ihletet. A „Ha messze méssz…” című kisregény egy művészeti kolónia mindennapjait mutatja be. A két főszereplő egyike a világtól megcsömörlött híres zenész, aki terápiás céllal költözött társaihoz. Közte, és a fájdalmas múltú, szép festőnő között kialakuló, sodró lendületű szerelem vezérfonalán keresztül jutunk el a meglepő befejezésig.
